function digitsOnly(value){
  return String(value || '').replace(/[^0-9]/g,'')
}

function employeeNameByNumber(value, role=null){
  const digits = digitsOnly(value)
  if(!digits) return ''
  const found = SERVICE_EMPLOYEE_NUMBERS.find(emp => {
    if(role && emp.role !== role) return false
    const oldNum = digitsOnly(emp.old)
    const newNum = digitsOnly(emp.new)
    return digits === oldNum || digits === newNum || (digits.length === 4 && (digits === oldNum.slice(-4) || digits === newNum.slice(-4)))
  })
  return found?.name || ''
}

function employeeNamesByNumbers(value, role=null){
  const raw = String(value || '')
  const numbers = raw.match(/\d+/g) || []
  const names = []
  numbers.forEach(num => {
    const name = employeeNameByNumber(num, role)
    if(name && !names.includes(name)) names.push(name)
  })
  return names.join(', ')
}

function techDisplayName(value){
  const mapped = employeeNamesByNumbers(value, 'tech')
  if(mapped) return mapped
  const raw = String(value || '').trim()
  return raw || 'Unassigned'
}

function employeeNumberMatches(value, emp){
  const digits = digitsOnly(value)
  if(!digits || !emp) return false
  const oldNum = digitsOnly(emp.old)
  const newNum = digitsOnly(emp.new)
  return digits === oldNum || digits === newNum || (digits.length === 4 && (digits === oldNum.slice(-4) || digits === newNum.slice(-4)))
}


function filterByAdvisor(rows = [], advisorName = '') {
  if(!advisorName) return rows
  return rows.filter(r => {
    const candidate = r.advisor || r.service_advisor || r.advisor_name || r.writer || r.writer_name || ''
    return isSameAdvisorName(candidate, advisorName)
  })
}

