function metricNumber(value){
  if(value === '-' || value === '' || value === null || value === undefined) return null
  const n = Number(String(value).replace('%','').replace(',','').trim())
  return Number.isFinite(n) ? n : null
}

function gradeFromNps(nps){
  const n = Number(nps ?? 0)
  if(n >= 90) return 'A+'
  if(n >= 80) return 'A'
  if(n >= 70) return 'B'
  if(n >= 60) return 'C'
  if(n >= 40) return 'D'
  return 'F'
}




function cleanVideoScoreValue(value){
  if(value === null || value === undefined || value === '') return null
  const match = String(value).match(/-?\d+(\.\d+)?/)
  if(!match) return null
  const n = Number(match[0])
  return Number.isFinite(n) ? n : null
}

function secondsFromDuration(value){
  if(value === null || value === undefined || value === '') return 0
  const text = String(value).trim()
  const parts = text.split(':').map(p => Number(p))
  if(parts.length === 2 && parts.every(Number.isFinite)){
    return (parts[0] * 60) + parts[1]
  }
  const n = Number(text)
  return Number.isFinite(n) ? n : 0
}

function formatSeconds(value){
  const total = Math.round(Number(value || 0))
  const m = Math.floor(total / 60)
  const s = String(total % 60).padStart(2,'0')
  return `${m}:${s}`
}

function normalizeTechName(value){
  let raw = String(value || '').trim()
  if(!raw) return ''
  if(raw.includes(',')){
    const parts = raw.split(',').map(x=>x.trim()).filter(Boolean)
    if(parts.length >= 2) raw = `${parts[1]} ${parts[0]}`
  }
  return raw
    .toLowerCase()
    .split(/\s+/)
    .map(p => p ? p[0].toUpperCase() + p.slice(1) : '')
    .join(' ')
}

function techNameKey(value){
  return normalizeTechName(value).toLowerCase().replace(/[^a-z0-9]/g,'')
}

function parseTechVideoReportWorkbook(workbook){
  const dealerWs = workbook.Sheets['Dealer View']
  const techWs = workbook.Sheets['Technician View']
  const leaderboardWs = workbook.Sheets['Technician Leaderboard']

  const dealerRows = dealerWs ? XLSX.utils.sheet_to_json(dealerWs, { defval: '' }) : []
  const techRows = techWs ? XLSX.utils.sheet_to_json(techWs, { defval: '' }) : []
  const leaderboardRows = leaderboardWs ? XLSX.utils.sheet_to_json(leaderboardWs, { defval: '' }) : []

  const byTech = new Map()

  function getOrCreate(name){
    const techName = normalizeTechName(name)
    if(!techName) return null
    const key = techNameKey(techName)
    if(!byTech.has(key)){
      byTech.set(key, {
        tech_name: techName,
        videos: 0,
        avg_score: 0,
        avg_duration_seconds: 0,
        avg_mileage: 0,
        green_count: 0,
        yellow_count: 0,
        red_count: 0,
        profanity_count: 0,
        customer_mpi_count: 0,
        leaderboard_score: null,
      })
    }
    return byTech.get(key)
  }

  dealerRows.forEach(row => {
    const item = getOrCreate(row.Technician)
    if(!item) return
    item.videos = Number(row['# Videos'] || item.videos || 0)
    item.avg_mileage = Number(row['Avg. Mileage'] || 0)
    item.avg_duration_seconds = secondsFromDuration(row['Avg. Duration'])
    const score = cleanVideoScoreValue(row['Avg. Score'])
    if(score !== null) item.avg_score = score
  })

  leaderboardRows.forEach(row => {
    const item = getOrCreate(row.Technician)
    if(!item) return
    const score = cleanVideoScoreValue(row.Score)
    if(score !== null){
      item.leaderboard_score = score
      if(!item.avg_score) item.avg_score = score
    }
  })

  const detailByTech = new Map()
  techRows.forEach(row => {
    const techName = normalizeTechName(row.Technician)
    if(!techName) return
    const key = techNameKey(techName)
    if(!detailByTech.has(key)){
      detailByTech.set(key, { count:0, scoreTotal:0, scoreCount:0, durationTotal:0, profanity:0, green:0, yellow:0, red:0, mpi:0 })
    }
    const d = detailByTech.get(key)
    d.count += 1
    const score = cleanVideoScoreValue(row.Score)
    if(score !== null){
      d.scoreTotal += score
      d.scoreCount += 1
      if(score >= 85) d.green += 1
      else if(score >= 70) d.yellow += 1
      else d.red += 1
    }
    d.durationTotal += secondsFromDuration(row['Video Duration'])
    if(String(row.Profanity || '').toLowerCase() === 'yes') d.profanity += 1
    if(String(row['Inspection Type'] || '').toLowerCase().includes('customer')) d.mpi += 1
  })

  detailByTech.forEach((d, key) => {
    const item = byTech.get(key) || getOrCreate(key)
    if(!item) return
    if(d.count > 0) item.videos = Math.max(item.videos || 0, d.count)
    if(d.scoreCount > 0) item.avg_score = d.scoreTotal / d.scoreCount
    if(d.count > 0) item.avg_duration_seconds = d.durationTotal / d.count
    item.profanity_count = d.profanity
    item.green_count = d.green
    item.yellow_count = d.yellow
    item.red_count = d.red
    item.customer_mpi_count = d.mpi
  })

  return Array.from(byTech.values()).filter(r => r.videos || r.avg_score)
}

function parseTechEfficiencyWorkbook(workbook){
  const ws = workbook.Sheets['WorkSheet'] || workbook.Sheets[workbook.SheetNames[0]]
  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  const LABOR_RATE = 200

  const rows = []
  raw.forEach((row) => {
    const techNumber = String(row[5] ?? '').trim()
    const last = String(row[3] ?? '').trim()
    const first = String(row[4] ?? '').trim()
    const produced = metricNumber(row[15])
    const worked = metricNumber(row[16])
    const guarantee = metricNumber(row[7])
    const wage = metricNumber(row[6])

    const mappedTechName = employeeNameByNumber(techNumber, 'tech')
    if(!techNumber || (!mappedTechName && (!last || !first))) return
    if(!Number.isFinite(produced) || !Number.isFinite(worked)) return
    if(techNumber.toLowerCase() === '#') return

    const techName = mappedTechName || `${first} ${last}`.replace(/\s+/g,' ').trim()
    const guaranteeHours = Number.isFinite(guarantee) && guarantee > 0 ? guarantee : 0
    const workedHours = Number.isFinite(worked) && worked > 0 ? worked : 0
    const producedHours = Number.isFinite(produced) ? produced : 0
    const techRate = Number.isFinite(wage) && wage > 0 ? wage : 0

    // Target rule:
    // If a tech has a guarantee, use the LOWER of worked hours or guarantee hours.
    // If there is no guarantee, use worked hours.
    const trackedTargetHours = guaranteeHours > 0
      ? Math.min(workedHours || guaranteeHours, guaranteeHours)
      : workedHours

    const efficiencyWorked = workedHours ? (producedHours / workedHours) * 100 : 0
    const efficiencyGuarantee = guaranteeHours ? (producedHours / guaranteeHours) * 100 : null
    const efficiencyTracked = trackedTargetHours ? (producedHours / trackedTargetHours) * 100 : 0

    const revenueProduced = producedHours * LABOR_RATE

    // Store gain/loss at customer labor rate against the tracked target.
    const revenueVarianceTracked = (producedHours - trackedTargetHours) * LABOR_RATE
    const revenueGainTracked = Math.max(0, revenueVarianceTracked)
    const opportunityLossTracked = Math.max(0, -revenueVarianceTracked)

    // Payroll guarantee exposure uses the employee rate and shortage to guarantee.
    // If worked is lower than guarantee, use worked as the target exposure.
    const guaranteeTargetForPayroll = guaranteeHours > 0 ? Math.min(workedHours || guaranteeHours, guaranteeHours) : workedHours
    const payrollShortHours = guaranteeTargetForPayroll ? Math.max(0, guaranteeTargetForPayroll - producedHours) : 0
    const payrollLoss = payrollShortHours * techRate

    rows.push({
      tech_name: techName,
      tech_number: techNumber.replace(/\.0$/,''),
      wage_rate: techRate,
      guarantee_hours: guaranteeHours,
      produced_hours: producedHours,
      worked_hours: workedHours,
      tracked_target_hours: trackedTargetHours,
      efficiency_worked: efficiencyWorked,
      efficiency_guarantee: efficiencyGuarantee,
      efficiency_tracked: efficiencyTracked,
      revenue_produced: revenueProduced,
      revenue_variance_tracked: revenueVarianceTracked,
      revenue_gain_worked: revenueGainTracked,
      opportunity_loss_worked: opportunityLossTracked,
      opportunity_loss_guarantee: payrollLoss,
      payroll_short_hours: payrollShortHours,
      revenue_gain_guarantee: Math.max(0, (producedHours - (guaranteeHours || workedHours)) * LABOR_RATE),
      labor_rate: LABOR_RATE,
    })
  })

  return rows
}


function parseProgramHealthWorkbook(workbook){
  const ws = workbook.Sheets['Table1'] || workbook.Sheets['Table'] || workbook.Sheets[workbook.SheetNames[0]]
  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  if(!raw.length) return []

  const headers = raw[0].map(h => String(h || '').trim())
  const metricRows = new Map()

  raw.slice(1).forEach(row => {
    const metric = String(row[0] || '').trim()
    if(metric) metricRows.set(metric.toLowerCase(), row)
  })

  const getMetric = (metricName, colIndex) => {
    const row = metricRows.get(String(metricName).toLowerCase())
    return row ? metricNumber(row[colIndex]) : null
  }

  const advisorCols = headers
    .map((name,index) => ({name,index}))
    .filter(({name}) => {
      if(!name) return false
      const advisor = canonicalAdvisorName(name)
      return isDashboardAdvisor(advisor)
    })

  return advisorCols.map(({name,index}) => ({
    advisor: canonicalAdvisorName(name),
    eligible_records: getMetric('Eligible Records', index) ?? 0,
    invitations_sent: getMetric('Invitations Sent', index) ?? 0,
    invitations_delivered: getMetric('Invitations Successfully Delivered', index) ?? 0,
    survey_responses: getMetric('Survey Responses', index) ?? 0,
    flagged_complete: getMetric('Flagged for Review - COMPLETE', index) ?? 0,
    email_capture_rate: getMetric('Email Capture Rate', index),
    bounce_rate: getMetric('Bounce Rate', index),
    response_rate: getMetric('Response Rate', index),
    reach_rate: getMetric('Reach Rate', index),
  }))
}

function parseMetricsPerformanceWorkbook(workbook){
  const ws = workbook.Sheets['Table1'] || workbook.Sheets['Table'] || workbook.Sheets[workbook.SheetNames[0]]
  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  if(!raw.length) return []

  const metricKey = (value) => String(value || '').toLowerCase().replace(/[^a-z0-9]/g,'')
  const headers = raw[0].map(h => String(h ?? '').trim())

  const metricRows = new Map()
  raw.slice(1).forEach((row) => {
    const metric = String(row[0] ?? '').trim()
    if(metric) metricRows.set(metricKey(metric), row)
  })

  const getMetric = (possibleNames, colIndex) => {
    const names = Array.isArray(possibleNames) ? possibleNames : [possibleNames]
    for(const name of names){
      const row = metricRows.get(metricKey(name))
      if(row) return metricNumber(row[colIndex])
    }
    return null
  }

  const advisorCols = headers
    .map((name, index) => ({ name, index, advisor: activeAdvisorName(name) || canonicalAdvisorName(name) }))
    .filter(({ name, advisor }) => {
      if(!name) return false
      return isDashboardAdvisor(advisor)
    })

  const parsed = advisorCols.map(({ advisor, index }) => ({
    advisor,
    sample_size: getMetric(['Sample Size (Main Survey)', 'Main Survey Sample Size'], index) ?? 0,
    final_nps: getMetric(['SVS Final Net Promoter Score', 'Final Net Promoter Score', 'Net Promoter Score'], index) ?? 0,
    issue_rate: getMetric(['Yes, I have an issue or concern I would like resolved', 'I have an issue or concern I would like resolved'], index) ?? 0,
    no_issue_rate: getMetric(['No'], index) ?? 0,
    optional_sample_size: getMetric(['Sample Size (Optional Survey)', 'Optional Survey Sample Size'], index) ?? 0,
    initiation_rating: getMetric(['Service Initiation Rating (1-10)', 'Service Initiation Rating'], index),
    consultant_rating: getMetric(['Service Consultant Rating (1-10)', 'Service Consultant Rating'], index),
    facility_rating: getMetric(['Service Facility Rating (1-10)', 'Service Facility Rating'], index),
    quality_rating: getMetric(['Service Quality Rating (1-10)', 'Service Quality Rating'], index),
    pickup_rating: getMetric(['Service Pick-Up/Wrap Up Rating (1-10)', 'Service Pick-Up/Wrap Up Rating', 'Service Pickup/Wrap Up Rating'], index),
    grade: gradeFromNps(getMetric(['SVS Final Net Promoter Score', 'Final Net Promoter Score', 'Net Promoter Score'], index) ?? 0),
  }))

  const byAdvisor = new Map(parsed.map(r => [r.advisor, r]))

  // Always include every active advisor in the dashboard.
  // If Kia export does not have a column yet, show a zero/blank row instead of hiding the advisor.
  ;(DASHBOARD_ADVISORS || []).forEach(advisor => {
    if(!byAdvisor.has(advisor)){
      byAdvisor.set(advisor, {
        advisor,
        sample_size: 0,
        final_nps: 0,
        issue_rate: 0,
        no_issue_rate: 0,
        optional_sample_size: 0,
        initiation_rating: null,
        consultant_rating: null,
        facility_rating: null,
        quality_rating: null,
        pickup_rating: null,
        grade: '—',
      })
    }
  })

  return Array.from(byAdvisor.values())
}


