function AdvisorMetricsPerformanceTable({ rows = [] }){
  const inputRows = Array.isArray(rows) ? rows : []
  const byAdvisor = new Map()

  inputRows.forEach(row => {
    const advisor = activeAdvisorName(row.advisor) || canonicalAdvisorName(row.advisor)
    if(isDashboardAdvisor(advisor)) byAdvisor.set(advisor, { ...row, advisor })
  })

  ;(DASHBOARD_ADVISORS || []).forEach(advisor => {
    if(!byAdvisor.has(advisor)){
      byAdvisor.set(advisor, {
        advisor,
        sample_size: 0,
        final_nps: 0,
        issue_rate: 0,
        no_issue_rate: 0,
        optional_sample_size: 0,
        initiation_rating: null,
        consultant_rating: null,
        facility_rating: null,
        quality_rating: null,
        pickup_rating: null,
        grade: '—',
      })
    }
  })

  const safeRows = Array.from(byAdvisor.values())
  const [sortConfig, setSortConfig] = useState({ key: 'final_nps', direction: 'desc' })

  function handleSort(key){
    setSortConfig((current) => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }))
  }

  const sortedRows = useMemo(() => {
    return [...safeRows].sort((a,b) => {
      const av = a[sortConfig.key]
      const bv = b[sortConfig.key]
      const an = Number(av)
      const bn = Number(bv)
      if(Number.isFinite(an) && Number.isFinite(bn)) return sortConfig.direction === 'asc' ? an - bn : bn - an
      const result = String(av ?? '').localeCompare(String(bv ?? ''), undefined, { numeric: true, sensitivity: 'base' })
      return sortConfig.direction === 'asc' ? result : -result
    })
  }, [safeRows, sortConfig])

  const rankedRows = safeRows.filter(r => Number(r.sample_size || 0) > 0)
  const top = [...rankedRows].sort((a,b)=>Number(b.final_nps ?? 0)-Number(a.final_nps ?? 0))[0]
  const needsAttention = [...rankedRows].sort((a,b)=>Number(a.final_nps ?? 0)-Number(b.final_nps ?? 0))[0]
  const totalSurveys = safeRows.reduce((sum,r)=>sum + Number(r.sample_size || 0), 0)

  return <div className="panel metrics-performance-panel">
    <div className="panel-head">
      <div>
        <div className="panel-title"><BarChart3 size={17}/> Advisor Metrics Performance</div>
        <div className="small">Imported from Kia Metrics Performance Excel. All active advisors are shown; blank export columns show as 0.</div>
      </div>
    </div>

    <div className="metrics-summary-row">
      <div><span>Top Performer</span><b>{top?.advisor ?? '—'}</b></div>
      <div><span>Highest NPS</span><b className="green">{top?.final_nps ?? '—'}</b></div>
      <div><span>Needs Attention</span><b className="red">{needsAttention?.advisor ?? '—'}</b></div>
      <div><span>Total Surveys</span><b>{totalSurveys}</b></div>
    </div>

    <div className="table-wrap">
      <table>
        <thead>
          <tr>
            <th><SortHeader label="Advisor" column="advisor" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Sample Size" column="sample_size" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Final NPS" column="final_nps" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Issue Rate" column="issue_rate" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="No Issue" column="no_issue_rate" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Consultant" column="consultant_rating" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th><SortHeader label="Quality" column="quality_rating" sortConfig={sortConfig} onSort={handleSort}/></th>
            <th>Grade</th>
          </tr>
        </thead>
        <tbody>
          {sortedRows.length === 0 ? (
            <tr><td colSpan="8" className="small">No Metrics Performance file uploaded yet.</td></tr>
          ) : sortedRows.map(row => (
            <tr key={row.advisor}>
              <td><b>{row.advisor}</b></td>
              <td>{row.sample_size ?? 0}</td>
              <td className={Number(row.final_nps || 0) >= 83 ? 'green' : Number(row.final_nps || 0) >= 70 ? 'orange' : 'red'}>{Number(row.final_nps || 0).toFixed(2)}</td>
              <td className={Number(row.issue_rate || 0) <= 3 ? 'green' : Number(row.issue_rate || 0) <= 8 ? 'orange' : 'red'}>{Number(row.issue_rate || 0).toFixed(2)}%</td>
              <td>{Number(row.no_issue_rate || 0).toFixed(2)}%</td>
              <td>{row.consultant_rating ?? '—'}</td>
              <td>{row.quality_rating ?? '—'}</td>
              <td><span className={`grade-pill ${String(row.grade || 'na').toLowerCase().replace(/[^a-z]/g,'')}`}>{row.grade || '—'}</span></td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  </div>
}


function cleanMoney(value){
  if(value === null || value === undefined || value === '') return null
  const n = Number(String(value).replace(/[$,]/g,'').trim())
  return Number.isFinite(n) ? n : null
}

function parseCdkDate(value){
  return excelDateToIso(value)
}

function parseCdkRepairPreinvoiceWorkbook(workbook){
  const repairSheet = workbook.Sheets['Repair Orders']
  const preInvoiceSheet = workbook.Sheets['Pre-Invoice']

  const repairRowsRaw = repairSheet ? XLSX.utils.sheet_to_json(repairSheet, { header: 1, defval: '' }) : []
  const repairHeaderIndex = repairRowsRaw.findIndex(row => String(row[0]).trim() === 'RO' && String(row[2]).trim() === 'Customer')
  const repairHeaders = repairHeaderIndex >= 0 ? repairRowsRaw[repairHeaderIndex] : []
  const repairRows = repairHeaderIndex >= 0
    ? repairRowsRaw.slice(repairHeaderIndex + 1).map(row => {
        const obj = {}
        repairHeaders.forEach((h,i)=>{ if(h) obj[String(h).trim()] = row[i] })
        return obj
      })
    : []

  const preRows = preInvoiceSheet ? XLSX.utils.sheet_to_json(preInvoiceSheet, { defval: '' }) : []

  return {
    repairOrders: repairRows.map((r) => ({
      ro: String(r['RO'] ?? '').trim().replace(/\.0$/, ''),
      tag: String(r['Tag'] ?? '').trim(),
      customer: String(r['Customer'] ?? '').trim(),
      model: String(r['Model'] ?? '').trim(),
      year: r['Year'] ? Number(r['Year']) : null,
      promise_date: parseCdkDate(r['Promise Date']),
      status: String(r['Status'] ?? '').trim(),
      advisor: titleCaseAdvisor(r['Advisor'] ?? ''),
      tech: employeeNamesByNumbers(r['Tech'], 'tech') || 'Unassigned',
      notes: String(r['Notes'] ?? '').trim(),
    })).filter(r => r.ro || r.customer),

    preInvoices: preRows.map((r) => ({
      ro: String(r['RO'] ?? '').trim().replace(/\.0$/, ''),
      customer: String(r['Customer'] ?? '').trim(),
      age: r['Age'] === '' ? null : Number(r['Age']),
      model: String(r['Model'] ?? '').trim(),
      year: r['Year'] ? Number(r['Year']) : null,
      status_desc: String(r['Status Desc'] ?? '').trim(),
      advisor: titleCaseAdvisor(r['Advisor'] ?? ''),
      tech: employeeNamesByNumbers(r['Tech'], 'tech') || 'Unassigned',
      invoice_amount: cleanMoney(r['Invoice $']),
      ro_estimate: cleanMoney(r['RO Estimate']),
      notes: String(r['Notes'] ?? '').trim(),
    })).filter(r => r.ro || r.customer),
  }
}


function parseServiceDailyLogOpenRoWorkbook(workbook){
  const ws = workbook.Sheets['Service Daily Log'] || workbook.Sheets[workbook.SheetNames[0]]
  if(!ws) return []
  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  const headerIndex = raw.findIndex(row => String(row?.[1] || '').trim().toLowerCase() === 'ro' && String(row?.[14] || '').toLowerCase().includes('status'))
  if(headerIndex < 0) return []

  function c(row, idx){ return row?.[idx] ?? '' }
  return raw.slice(headerIndex + 1).map(row => {
    const ro = String(c(row,1) || '').trim().replace(/\.0$/, '')
    if(!ro || ro.toLowerCase().includes('no repair orders')) return null
    const advisor = activeAdvisorIdMap(c(row,15))
    const promise = parseCdkDate(c(row,8))
    const status = String(c(row,14) || '').trim()
    const serviceRequest = String(c(row,17) || '').trim()
    const laborType = String(c(row,18) || '').trim()
    const tag = String(c(row,2) || '').trim()
    const customer = String(c(row,3) || '').trim()
    const model = String(c(row,6) || '').trim()
    const yearValue = Number(c(row,7) || 0)
    const tech = employeeNamesByNumbers(c(row,16), 'tech') || 'Unassigned'
    const sor = String(c(row,12) || '').trim()
    const internalCustomer = String(c(row,13) || '').trim()
    const notes = [serviceRequest, laborType ? `Labor Type: ${laborType}` : '', sor ? `SOR: ${sor}` : '', internalCustomer ? `I/C: ${internalCustomer}` : ''].filter(Boolean).join(' | ')
    return {
      ro,
      tag,
      customer,
      model,
      year: Number.isFinite(yearValue) && yearValue > 0 ? yearValue : null,
      promise_date: promise,
      status,
      advisor,
      tech,
      notes,
    }
  }).filter(r => r && r.ro && r.advisor)
}

