function SafeSortableTable({ title, rows = [], columns = [], defaultSort = 'ro', moneyColumns = [], numberColumns = [] }) {
  const [search,setSearch] = useState('')
  const [sortConfig,setSortConfig] = useState({ key: defaultSort, direction: 'asc' })

  function sortBy(key){
    setSortConfig((current)=>({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }))
  }

  function sortValue(row,key){
    const value = row[key]
    if(numberColumns.includes(key) || moneyColumns.includes(key) || key === 'ro'){
      const n = Number(String(value ?? '').replace(/[$,]/g,'').replace(/[^\d.-]/g,''))
      return Number.isFinite(n) ? n : 0
    }
    if(key.includes('date')){
      const d = new Date(value || '')
      return Number.isNaN(d.getTime()) ? 0 : d.getTime()
    }
    return String(value ?? '').toLowerCase()
  }

  const filtered = [...rows]
    .filter(r => Object.values(r || {}).join(' ').toLowerCase().includes(search.toLowerCase()))
    .sort((a,b)=>{
      const av = sortValue(a, sortConfig.key)
      const bv = sortValue(b, sortConfig.key)
      if(typeof av === 'number' && typeof bv === 'number'){
        return sortConfig.direction === 'asc' ? av - bv : bv - av
      }
      const result = String(av).localeCompare(String(bv), undefined, { numeric:true, sensitivity:'base' })
      return sortConfig.direction === 'asc' ? result : -result
    })

  return (
    <div className="panel">
      <div className="panel-head">
        <div>
          <div className="panel-title">{title}</div>
          <div className="small">{filtered.length} showing · {rows.length} total</div>
        </div>
        <input className="search" placeholder="Search..." value={search} onChange={e=>setSearch(e.target.value)} />
      </div>
      <div className="table-wrap ro-table-wrap">
        <table>
          <thead>
            <tr>
              {columns.map(col => (
                <th key={col.key}>
                  <button className="sort-header" onClick={()=>sortBy(col.key)}>
                    {col.label} {sortConfig.key === col.key ? (sortConfig.direction === 'asc' ? '↑' : '↓') : '↕'}
                  </button>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map((row,idx)=>(
              <tr key={`${row.id || row.ro}-${idx}`} className={rowClassName ? rowClassName(row) : ''}>
                {columns.map(col => {
                  const value = row[col.key]
                  const display = moneyColumns.includes(col.key)
                    ? `$${Math.round(Number(value || 0)).toLocaleString()}`
                    : (value ?? '—')
                  return <td key={col.key}>{display || '—'}</td>
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}

