function ageTone(days){
  const n = Number(days || 0)
  if(n >= 10) return 'red'
  if(n >= 6) return 'orange'
  if(n >= 3) return 'yellow'
  return 'green'
}

function statusTone(status){
  const text = String(status || '').toLowerCase()
  if(text.includes('ready')) return 'green'
  if(text.includes('all lab')) return 'orange'
  if(text.includes('preassign')) return 'blue'
  if(text.includes('open')) return 'yellow'
  if(text.includes('wait') || text.includes('hold')) return 'red'
  return 'gray'
}

function statusCircleTitle(status){
  const text = String(status || '').trim()
  return text || 'Other / Unknown'
}

function roPriority(row){
  const days = Number(row?.days_past_promise || 0)
  const status = String(row?.status || '').toLowerCase()
  if(days >= 7) return 'High'
  if(days >= 3) return 'Watch'
  if(status.includes('ready')) return 'Ready'
  return 'Normal'
}

function roAgeBucket(days){
  const n = Number(days || 0)
  if(n >= 10) return '10+ Days'
  if(n >= 6) return '6-9 Days'
  if(n >= 3) return '3-5 Days'
  return '0-2 Days'
}



function workloadNumberTone(metric, value){
  const n = Number(value || 0)
  if(metric === 'open_ros' || metric === 'assigned'){
    if(n >= 26) return 'red'
    if(n >= 19) return 'orange'
    if(n >= 11) return 'yellow'
    return 'green'
  }
  if(metric === 'avg_days' || metric === 'oldest'){
    if(n >= 10) return 'red'
    if(n >= 6) return 'orange'
    if(n >= 3) return 'yellow'
    return 'green'
  }
  if(metric === 'over_7_days'){
    if(n >= 9) return 'red'
    if(n >= 6) return 'orange'
    if(n >= 3) return 'yellow'
    return 'green'
  }
  if(metric === 'ready'){
    if(n >= 5) return 'green'
    if(n >= 2) return 'yellow'
    return 'red'
  }
  if(metric === 'all_labor_posted'){
    if(n >= 8) return 'orange'
    if(n >= 3) return 'blue'
    return 'gray'
  }
  return 'gray'
}

function workloadHealth(row, type){
  const openCount = Number(type === 'advisor' ? row.open_ros : row.assigned || 0)
  const over7 = Number(row.over_7_days || 0)
  const avg = Number(row.avg_days || 0)
  if(over7 >= 9 || avg >= 10 || openCount >= 26) return { label:'Needs Attention', tone:'red' }
  if(over7 >= 6 || avg >= 6 || openCount >= 19) return { label:'Busy', tone:'orange' }
  if(over7 >= 3 || avg >= 3 || openCount >= 11) return { label:'Watch', tone:'yellow' }
  return { label:'Healthy', tone:'green' }
}

function WorkloadCardGrid({ title, rows = [], type = 'advisor' }){
  const [search,setSearch] = useState('')
  const [sortConfig,setSortConfig] = useState({ key: type === 'advisor' ? 'open_ros' : 'assigned', direction:'desc' })
  const nameKey = type === 'advisor' ? 'advisor' : 'tech'
  const countKey = type === 'advisor' ? 'open_ros' : 'assigned'

  function sortBy(key){
    setSortConfig((current)=>({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }))
  }

  const filtered = rows
    .filter(r => String(r?.[nameKey] || '').toLowerCase().includes(search.toLowerCase()))
    .sort((a,b)=>{
      const av = a[sortConfig.key]
      const bv = b[sortConfig.key]
      const an = Number(av)
      const bn = Number(bv)
      if(Number.isFinite(an) && Number.isFinite(bn)){
        return sortConfig.direction === 'asc' ? an - bn : bn - an
      }
      const result = String(av || '').localeCompare(String(bv || ''), undefined, { numeric:true, sensitivity:'base' })
      return sortConfig.direction === 'asc' ? result : -result
    })

  const columns = [
    { key:'health', label:'', className:'center' },
    { key:nameKey, label:type === 'advisor' ? 'Advisor' : 'Technician' },
    { key:countKey, label:type === 'advisor' ? 'Open ROs' : 'Assigned' },
    { key:'over_7_days', label:'7+ Days' },
    { key:'avg_days', label:'Avg Days' },
    { key:'oldest', label:'Oldest' },
    { key:'ready', label:'Ready' },
    { key:'all_labor_posted', label:'Labor Posted' },
    { key:'health_label', label:'Health' },
  ]

  function renderCell(row, col){
    const health = workloadHealth(row,type)
    if(col.key === 'health') return <span className={`ops-status-dot ${health.tone}`} title={health.label}></span>
    if(col.key === nameKey) return <span className="ops-person-name">{row[nameKey] || 'Unknown'}</span>
    if(col.key === 'health_label') return <span className={`ops-health-chip ${health.tone}`}>{health.label}</span>
    if(['over_7_days','avg_days','oldest','ready','all_labor_posted',countKey].includes(col.key)){
      const tone = workloadNumberTone(col.key, row[col.key])
      return <span className={`ops-number ${tone}`}>{row[col.key] ?? 0}</span>
    }
    return row[col.key] ?? '—'
  }

  return (
    <div className="panel ops-panel workload-table-panel">
      <div className="panel-head ro-panel-head ops-panel-head">
        <div>
          <div className="panel-title">{title}</div>
          <div className="small">{filtered.length} showing · {rows.length} total</div>
        </div>
        <input className="search workload-search" placeholder={`Search ${type === 'advisor' ? 'advisor' : 'technician'}...`} value={search} onChange={e=>setSearch(e.target.value)} />
      </div>
      <div className="table-wrap ops-table-wrap compact-workload-table">
        <table>
          <thead>
            <tr>
              {columns.map(col => (
                <th key={col.key} className={col.className || ''}>
                  {col.key === 'health'
                    ? <span>●</span>
                    : <button className="sort-header" onClick={()=>sortBy(col.key === 'health_label' ? countKey : col.key)}>{col.label} {sortConfig.key === col.key ? (sortConfig.direction === 'asc' ? '↑' : '↓') : ''}</button>}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map((row,idx)=>(
              <tr key={`${row[nameKey] || 'unknown'}-${idx}`} className={`ops-workload-row ${workloadHealth(row,type).tone}`}>
                {columns.map(col => <td key={col.key} className={col.className || ''}>{renderCell(row,col)}</td>)}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}

function CdkActualSortableTable({ title, rows = [], columns = [], defaultSort = 'ro', moneyColumns = [], numberColumns = [], rowClassName, filterColumns = [], enableDetail = false }) {
  const [search,setSearch] = useState('')
  const [sortConfig,setSortConfig] = useState({ key: defaultSort, direction: defaultSort === 'days_past_promise' ? 'desc' : 'asc' })
  const [filters,setFilters] = useState({})
  const [selectedRow,setSelectedRow] = useState(null)

  function sortBy(key){
    setSortConfig((current)=>({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }))
  }

  function sortValue(row,key){
    const value = row[key]
    if(numberColumns.includes(key) || moneyColumns.includes(key) || key === 'ro'){
      const n = Number(String(value ?? '').replace(/[$,]/g,'').replace(/[^\d.-]/g,''))
      return Number.isFinite(n) ? n : 0
    }
    if(key.includes('date')){
      const d = new Date(value || '')
      return Number.isNaN(d.getTime()) ? 0 : d.getTime()
    }
    return String(value ?? '').toLowerCase()
  }

  const filterOptions = filterColumns.reduce((acc,key)=>{
    acc[key] = Array.from(new Set(rows.map(r => String(r?.[key] || '').trim()).filter(Boolean))).sort((a,b)=>a.localeCompare(b, undefined, {numeric:true}))
    return acc
  }, {})

  const filtered = [...rows]
    .filter(r => Object.values(r || {}).join(' ').toLowerCase().includes(search.toLowerCase()))
    .filter(r => filterColumns.every(key => !filters[key] || String(r?.[key] || '') === filters[key]))
    .sort((a,b)=>{
      const av = sortValue(a, sortConfig.key)
      const bv = sortValue(b, sortConfig.key)
      if(typeof av === 'number' && typeof bv === 'number'){
        return sortConfig.direction === 'asc' ? av - bv : bv - av
      }
      const result = String(av).localeCompare(String(bv), undefined, { numeric:true, sensitivity:'base' })
      return sortConfig.direction === 'asc' ? result : -result
    })

  function renderCell(row, col){
    const value = row[col.key]
    if(col.key === 'status_indicator') return <span className={`ro-status-dot ${statusTone(row.status)}`} title={statusCircleTitle(row.status)} aria-label={statusCircleTitle(row.status)}></span>
    if(col.key === 'priority') return <span className={`ro-priority-pill ${String(value || '').toLowerCase()}`}>{value || roPriority(row)}</span>
    if(moneyColumns.includes(col.key)) return `$${Math.round(Number(value || 0)).toLocaleString()}`
    if(col.key === 'days_past_promise') return <span className={`ro-age-pill ${ageTone(value)}`}>{value ?? 0}</span>
    if(col.key === 'status') return <span className={`ro-status-pill ${statusTone(value)}`}>{value || '—'}</span>
    if(col.key === 'tech') return techDisplayName(value)
    if(col.key === 'service_request') return String(row.service_request || row.notes || '').split(' | Labor Type:')[0] || '—'
    if(col.key === 'labor_type') return (row.labor_type || String(row.notes || '').match(/Labor Type: ([^|]+)/)?.[1] || '—').trim()
    if(col.key === 'open_date') return row.open_date || '—'
    return value || '—'
  }

  const selected = selectedRow && filtered.find((r,idx)=>`${r.id || r.ro}-${idx}` === selectedRow)

  return (
    <div className="panel">
      <div className="panel-head ro-panel-head">
        <div>
          <div className="panel-title">{title}</div>
          <div className="small">{filtered.length} showing · {rows.length} total</div>
        </div>
        <div className="ro-filter-bar">
          <input className="search" placeholder="Search RO, customer, vehicle, advisor, tech..." value={search} onChange={e=>setSearch(e.target.value)} />
          {filterColumns.map(key => (
            <select key={key} className="ro-filter-select" value={filters[key] || ''} onChange={e=>setFilters({...filters, [key]:e.target.value})}>
              <option value="">All {columns.find(c=>c.key===key)?.label || key}</option>
              {filterOptions[key].map(option => <option key={option} value={option}>{option}</option>)}
            </select>
          ))}
        </div>
      </div>
      <div className="table-wrap ro-table-wrap">
        <table>
          <thead>
            <tr>
              {columns.map(col => (
                <th key={col.key}>
                  <button className="sort-header" onClick={()=>sortBy(col.key)}>
                    {col.label} {sortConfig.key === col.key ? (sortConfig.direction === 'asc' ? '↑' : '↓') : '↕'}
                  </button>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.map((row,idx)=>{
              const key = `${row.id || row.ro}-${idx}`
              return (
                <tr key={key} className={`${rowClassName ? rowClassName(row) : ''} ${enableDetail ? 'clickable-row' : ''}`} onClick={()=>enableDetail && setSelectedRow(selectedRow === key ? null : key)}>
                  {columns.map(col => <td key={col.key}>{renderCell(row, col)}</td>)}
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>
      {enableDetail && selected && (
        <div className="ro-detail-drawer">
          <div><b>RO #{selected.ro}</b><span>{selected.customer || 'No customer listed'}</span></div>
          <div><b>Advisor</b><span>{selected.advisor || '—'}</span></div>
          <div><b>Technician</b><span>{techDisplayName(selected.tech)}</span></div>
          <div><b>Status</b><span>{selected.status || '—'}</span></div>
          <div><b>Promise Date</b><span>{selected.promise_date || '—'}</span></div>
          <div><b>Days Past Promise</b><span>{selected.days_past_promise ?? 0}</span></div>
          <div className="ro-detail-wide"><b>Service Request</b><span>{selected.service_request || String(selected.notes || '').split(' | Labor Type:')[0] || '—'}</span></div>
        </div>
      )}
    </div>
  )
}


function CdkActualRepairOrdersPage({ repairOrders: initialRepairOrders = [], advisorFilter = '' }) {
  const [rows,setRows] = useState(initialRepairOrders)
  const [loading,setLoading] = useState(false)
  const [error,setError] = useState('')

  useEffect(()=>{
    let active = true
    async function load(){
      try{
        setLoading(true)
        setError('')
        const data = await getRepairOrders()
        if(active) setRows(advisorFilter ? filterByAdvisor(Array.isArray(data) ? data : [], advisorFilter) : (Array.isArray(data) ? data : []))
      }catch(e){
        console.error(e)
        if(active) setError(e.message || String(e))
      }finally{
        if(active) setLoading(false)
      }
    }
    load()
    return ()=>{ active = false }
  }, [advisorFilter])

  const today = new Date()
  today.setHours(0,0,0,0)
  const withAge = rows.map(r => {
    const d = r.promise_date ? new Date(r.promise_date) : null
    const valid = d && !Number.isNaN(d.getTime())
    if(valid) d.setHours(0,0,0,0)
    const days_past_promise = valid ? Math.max(0, Math.floor((today - d) / 86400000)) : 0
    const techName = techDisplayName(r.tech)
    const priority = roPriority({...r, days_past_promise})
    return {...r, tech: techName, days_past_promise, age_bucket: roAgeBucket(days_past_promise), priority, service_request: String(r.service_request || r.notes || '').split(' | Labor Type:')[0] || ''}
  })
  const total = withAge.length
  const open = withAge.filter(r => String(r.status || '').toLowerCase().includes('open')).length
  const ready = withAge.filter(r => String(r.status || '').toLowerCase().includes('ready')).length
  const allLaborPosted = withAge.filter(r => String(r.status || '').toLowerCase().includes('all lab')).length
  const preassigned = withAge.filter(r => String(r.status || '').toLowerCase().includes('preassign')).length
  const dueToday = withAge.filter(r => Number(r.days_past_promise || 0) === 0).length
  const over7 = withAge.filter(r => Number(r.days_past_promise || 0) >= 7).length
  const oldest = total ? Math.max(...withAge.map(r => Number(r.days_past_promise || 0))) : 0
  const avgAge = total ? withAge.reduce((s,r)=>s + Number(r.days_past_promise || 0),0) / total : 0

  const advisorPipeline = Object.values(withAge.reduce((acc,r)=>{
    const key = activeAdvisorName(r.advisor) || r.advisor || 'Unknown'
    if(!acc[key]) acc[key] = { advisor:key, open_ros:0, avg_days:0, ready:0, all_labor_posted:0, over_7_days:0, oldest:0 }
    acc[key].open_ros += 1
    acc[key].avg_days += Number(r.days_past_promise || 0)
    if(String(r.status || '').toLowerCase().includes('ready')) acc[key].ready += 1
    if(String(r.status || '').toLowerCase().includes('all lab')) acc[key].all_labor_posted += 1
    if(Number(r.days_past_promise || 0) >= 7) acc[key].over_7_days += 1
    acc[key].oldest = Math.max(acc[key].oldest, Number(r.days_past_promise || 0))
    return acc
  }, {})).map(r => ({...r, avg_days: r.open_ros ? Number((r.avg_days / r.open_ros).toFixed(1)) : 0})).filter(r => isDashboardAdvisor(r.advisor) || advisorFilter)

  const techPipeline = Object.values(withAge.reduce((acc,r)=>{
    const key = techDisplayName(r.tech) || 'Unassigned'
    if(!acc[key]) acc[key] = { tech:key, assigned:0, avg_days:0, ready:0, all_labor_posted:0, over_7_days:0, oldest:0 }
    acc[key].assigned += 1
    acc[key].avg_days += Number(r.days_past_promise || 0)
    if(String(r.status || '').toLowerCase().includes('ready')) acc[key].ready += 1
    if(String(r.status || '').toLowerCase().includes('all lab')) acc[key].all_labor_posted += 1
    if(Number(r.days_past_promise || 0) >= 7) acc[key].over_7_days += 1
    acc[key].oldest = Math.max(acc[key].oldest, Number(r.days_past_promise || 0))
    return acc
  }, {})).map(r => ({...r, avg_days: r.assigned ? Number((r.avg_days / r.assigned).toFixed(1)) : 0}))

  return (
    <>
      {error && <div className="error">Repair Orders load failed: {error}</div>}
      {loading && <div className="management-status">Loading Repair Orders...</div>}
      <div className="simple-csi-kpis ro-command-cards">
        <div className="card"><div className="label">Total Open ROs</div><div className="value green">{total}</div></div>
        <div className="card"><div className="label">Ready To Post</div><div className="value green">{ready}</div></div>
        <div className="card"><div className="label">Opened</div><div className="value blue">{open}</div></div>
        <div className="card"><div className="label">All Labor Posted</div><div className="value orange">{allLaborPosted}</div></div>
        <div className="card"><div className="label">Preassigned</div><div className="value blue">{preassigned}</div></div>
        <div className="card"><div className="label">Avg Days Past Promise</div><div className="value">{avgAge.toFixed(1)}</div></div>
        <div className="card"><div className="label">Oldest RO</div><div className="value red">{oldest}</div></div>
        <div className="card"><div className="label">Due / On Promise Today</div><div className="value orange">{dueToday}</div></div>
        <div className="card"><div className="label">7+ Days Past Promise</div><div className="value red">{over7}</div></div>
      </div>
      {!advisorFilter && <div className="ro-workload-grid">
        <WorkloadCardGrid title="Advisor Workload" rows={advisorPipeline} type="advisor" />
        <WorkloadCardGrid title="Technician Workload" rows={techPipeline} type="tech" />
      </div>}
      <CdkActualSortableTable
        title="Open RO Detail"
        rows={withAge}
        defaultSort="days_past_promise"
        columns={[
          {key:'status_indicator', label:'●'},
          {key:'ro', label:'RO #'},
          {key:'open_date', label:'RO Open Date'},
          {key:'advisor', label:'Advisor'},
          {key:'tech', label:'Technician'},
          {key:'customer', label:'Customer'},
          {key:'model', label:'Vehicle'},
          {key:'status', label:'Status'},
          {key:'promise_date', label:'Promise Date'},
          {key:'days_past_promise', label:'Days Past Promise'},
          {key:'age_bucket', label:'Age'},
          {key:'priority', label:'Priority'},
          {key:'labor_type', label:'Labor Type'},
          {key:'service_request', label:'Service Request'},
        ]}
        numberColumns={['days_past_promise','ro']}
        filterColumns={['advisor','tech','status','age_bucket','priority','labor_type']}
        enableDetail={true}
      />
      <div className="small ro-source-note">Note: the current CDK Open RO workbook includes Promise Date, but does not include a separate RO open date field. The RO Open Date column will populate automatically if that field is added to the export.</div>
    </>
  )
}

