function AdvisorCsiScorecard({ programHealthMetrics = [], surveyResults = [], metricsPerformance = [], user }){
  const activeAdvisors = DASHBOARD_ADVISORS || []
  const healthByAdvisor = new Map()
  const metricsByAdvisor = new Map()

  ;(programHealthMetrics || []).forEach(row => {
    const advisor = activeAdvisorName(row.advisor) || canonicalAdvisorName(row.advisor)
    if(advisor) healthByAdvisor.set(advisor, row)
  })

  ;(metricsPerformance || []).forEach(row => {
    const advisor = activeAdvisorName(row.advisor) || canonicalAdvisorName(row.advisor)
    if(advisor) metricsByAdvisor.set(advisor, row)
  })

  const surveysByAdvisor = new Map()
  ;(surveyResults || []).forEach(row => {
    const advisor = activeAdvisorName(row.advisor) || canonicalAdvisorName(row.advisor)
    if(!advisor || !isDashboardAdvisor(advisor)) return

    const rawScore = row.likelihood_to_recommend ?? row.ksi ?? row.score ?? row.survey_score
    const score = Number(String(rawScore ?? '').replace('%','').trim())
    if(!Number.isFinite(score)) return

    if(!surveysByAdvisor.has(advisor)) surveysByAdvisor.set(advisor, [])
    surveysByAdvisor.get(advisor).push(score)
  })

  const rows = activeAdvisors.map(advisor => {
    const health = healthByAdvisor.get(advisor) || {}
    const metrics = metricsByAdvisor.get(advisor) || {}
    const scores = surveysByAdvisor.get(advisor) || []

    const sent = Number(health.invitations_sent ?? health.sent ?? 0)
    const completed = scores.length || Number(health.survey_responses ?? metrics.sample_size ?? 0)
    const responseRate = sent ? (completed / sent) * 100 : Number(health.response_rate ?? 0)
    const avgScore = scores.length ? scores.reduce((sum, n)=>sum+n, 0) / scores.length : null

    const tens = scores.filter(n => n === 10).length
    const nines = scores.filter(n => n === 9).length
    const reds = scores.filter(n => n <= 6).length
    const promoters = scores.filter(n => n >= 9).length
    const detractors = scores.filter(n => n <= 6).length
    const nps = scores.length ? ((promoters / scores.length) * 100) - ((detractors / scores.length) * 100) : Number(metrics.final_nps ?? 0)

    return {
      advisor,
      sent,
      completed,
      responseRate,
      avgScore,
      nps,
      tens,
      nines,
      reds,
      scoreCount: scores.length,
    }
  }).filter(row => user?.role === 'advisor' ? isSameAdvisorName(row.advisor, user.advisor) : true)

  const sortedRows = [...rows].sort((a,b) => Number(b.nps || 0) - Number(a.nps || 0))
  const top = sortedRows[0]
  const needsCoaching = [...rows].filter(r => r.scoreCount > 0).sort((a,b) => Number(a.nps || 0) - Number(b.nps || 0))[0]

  function fmtPct(value){
    const n = Number(value)
    return Number.isFinite(n) ? `${n.toFixed(1)}%` : '—'
  }

  function fmtNum(value){
    const n = Number(value)
    return Number.isFinite(n) ? n.toFixed(1) : '—'
  }

  function npsClass(nps){
    const n = Number(nps || 0)
    if(n >= 85) return 'green'
    if(n >= 70) return 'orange'
    return 'red'
  }

  return (
    <div className="panel advisor-csi-scorecard-panel">
      <div className="panel-head">
        <div>
          <div className="panel-title"><Trophy size={17}/> Advisor CSI Scorecard</div>
          <div className="small">Combines Program Health, Survey Results, and Metrics Performance. Advisors see only their own scorecard.</div>
        </div>
      </div>

      {user?.role !== 'advisor' && (
        <div className="scorecard-summary-row">
          <div><span></span><b className="green">{top?.advisor ?? '—'}</b></div>
          <div><span>Highest NPS</span><b className={npsClass(top?.nps)}>{Number(top?.nps ?? 0).toFixed(1)}</b></div>
          <div><span>Coaching Focus</span><b className="orange">{needsCoaching?.advisor ?? '—'}</b></div>
          <div><span>Total Responses</span><b>{rows.reduce((sum,r)=>sum + Number(r.completed || 0), 0)}</b></div>
        </div>
      )}

      <div className="table-wrap">
        <table>
          <thead>
            <tr>
              <th>Advisor</th>
              <th>Surveys Sent</th>
              <th>Completed</th>
              <th>Response %</th>
              <th>Avg Score</th>
              <th>NPS</th>
              <th>10s</th>
              <th>9s</th>
              <th>Reds</th>
            </tr>
          </thead>
          <tbody>
            {sortedRows.length === 0 ? (
              <tr><td colSpan="9" className="small">No scorecard data available yet.</td></tr>
            ) : sortedRows.map(row => (
              <tr key={row.advisor}>
                <td><b>{row.advisor}</b></td>
                <td>{row.sent || 0}</td>
                <td>{row.completed || 0}</td>
                <td className={Number(row.responseRate || 0) >= 15 ? 'green' : Number(row.responseRate || 0) >= 8 ? 'orange' : 'red'}>{fmtPct(row.responseRate)}</td>
                <td className={Number(row.avgScore || 0) >= 9 ? 'green' : Number(row.avgScore || 0) >= 7 ? 'orange' : 'red'}>{row.avgScore === null ? '—' : fmtNum(row.avgScore)}</td>
                <td className={npsClass(row.nps)}>{Number(row.nps || 0).toFixed(1)}</td>
                <td className="green">{row.tens}</td>
                <td className="orange">{row.nines}</td>
                <td className={row.reds > 0 ? 'red' : 'green'}>{row.reds}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}



function TechVideoPerformancePanel({ rows = [], efficiencyRows = [] }){
  const effByTech = new Map()
  ;(efficiencyRows || []).forEach(row => {
    effByTech.set(techNameKey(row.tech_name), row)
  })

  const videoRows = (Array.isArray(rows) ? rows : [])
    .filter(r => r.tech_name)
    .map(r => {
      const eff = effByTech.get(techNameKey(r.tech_name)) || {}
      return {
        ...r,
        efficiency_worked: eff.efficiency_worked ?? null,
        produced_hours: eff.produced_hours ?? null,
      }
    })
    .sort((a,b) => Number(b.avg_score || 0) - Number(a.avg_score || 0))

  const totalVideos = videoRows.reduce((sum,r)=>sum + Number(r.videos || 0), 0)
  const avgScore = videoRows.length ? videoRows.reduce((sum,r)=>sum + Number(r.avg_score || 0), 0) / videoRows.length : 0
  const topVideo = videoRows[0]
  const coaching = [...videoRows].filter(r => Number(r.videos || 0) > 0).sort((a,b)=>Number(a.avg_score || 0)-Number(b.avg_score || 0))[0]

  function pct(value){
    const n = Number(value || 0)
    return Number.isFinite(n) ? `${n.toFixed(1)}%` : '—'
  }

  function scoreClass(value){
    const n = Number(value || 0)
    if(n >= 85) return 'green'
    if(n >= 70) return 'orange'
    return 'red'
  }

  function duration(value){
    return formatSeconds(value)
  }

  return (
    <div className="panel tech-video-panel">
      <div className="panel-head">
        <div>
          <div className="panel-title"><Video size={17}/> Video Inspection Performance</div>
          <div className="small">Imported from the combined MyKaarma technician report. Combines video score with technician efficiency.</div>
        </div>
      </div>

      <div className="video-summary-row">
        <div><span>Total Videos</span><b>{totalVideos}</b></div>
        <div><span>Avg Video Score</span><b className={scoreClass(avgScore)}>{avgScore.toFixed(1)}</b></div>
        <div><span>Top Video Score</span><b className="green">{topVideo?.tech_name ?? '—'}</b></div>
        <div><span>Video Coaching</span><b className="orange">{coaching?.tech_name ?? '—'}</b></div>
      </div>

      <div className="table-wrap">
        <table>
          <thead>
            <tr>
              <th>Rank</th>
              <th>Technician</th>
              <th>Eff. Worked</th>
              <th>Produced</th>
              <th>Videos</th>
              <th>Avg Score</th>
              <th>Avg Duration</th>
              <th>Green</th>
              <th>Yellow</th>
              <th>Red</th>
              <th>Profanity</th>
            </tr>
          </thead>
          <tbody>
            {videoRows.length === 0 ? (
              <tr><td colSpan="11" className="small">No video inspection report uploaded yet.</td></tr>
            ) : videoRows.map((r,idx)=>(
              <tr key={`${r.tech_name}-${idx}`}>
                <td>{idx + 1}</td>
                <td><b>{r.tech_name}</b></td>
                <td className={Number(r.efficiency_worked || 0) >= 100 ? 'green' : Number(r.efficiency_worked || 0) >= 75 ? 'orange' : 'red'}>{r.efficiency_worked === null ? '—' : pct(r.efficiency_worked)}</td>
                <td>{r.produced_hours === null ? '—' : Number(r.produced_hours || 0).toFixed(1)}</td>
                <td>{r.videos || 0}</td>
                <td className={scoreClass(r.avg_score)}><b>{Number(r.avg_score || 0).toFixed(1)}</b></td>
                <td>{duration(r.avg_duration_seconds)}</td>
                <td className="green">{r.green_count || 0}</td>
                <td className="orange">{r.yellow_count || 0}</td>
                <td className={(r.red_count || 0) > 0 ? 'red' : ''}>{r.red_count || 0}</td>
                <td className={(r.profanity_count || 0) > 0 ? 'red' : ''}>{r.profanity_count || 0}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  )
}

function TechEfficiencyView({ rows = [], videoRows = [] }){
  const techRows = (Array.isArray(rows) ? rows : []).filter(r => r.tech_name)

  const sortedRows = useMemo(() => {
    return [...techRows].sort((a,b) => Number(b.efficiency_worked || 0) - Number(a.efficiency_worked || 0))
  }, [techRows])

  const totalProduced = techRows.reduce((sum,r)=>sum + Number(r.produced_hours || 0), 0)
  const totalWorked = techRows.reduce((sum,r)=>sum + Number(r.worked_hours || 0), 0)
  const totalGuarantee = techRows.reduce((sum,r)=>sum + Number(r.guarantee_hours || 0), 0)
  const totalRevenue = techRows.reduce((sum,r)=>sum + Number(r.revenue_produced || 0), 0)
  const totalLossWorked = techRows.reduce((sum,r)=>sum + Number(r.opportunity_loss_worked || 0), 0)
  const totalPayrollLoss = techRows.reduce((sum,r)=>sum + Number(r.opportunity_loss_guarantee || 0), 0)
  const totalGainWorked = techRows.reduce((sum,r)=>sum + Number(r.revenue_gain_worked || 0), 0)
  const totalTrackedTarget = techRows.reduce((sum,r)=>sum + Number(r.tracked_target_hours || 0), 0)
  const shopEfficiencyTracked = totalTrackedTarget ? (totalProduced / totalTrackedTarget) * 100 : 0
  const above100 = techRows.filter(r => Number(r.efficiency_worked || 0) >= 100).length
  const below75 = techRows.filter(r => Number(r.efficiency_worked || 0) < 75).length
  const shopEfficiencyWorked = totalWorked ? (totalProduced / totalWorked) * 100 : 0
  const shopEfficiencyGuarantee = totalGuarantee ? (totalProduced / totalGuarantee) * 100 : 0
  const topTech = sortedRows[0]
  const lowTech = [...techRows].filter(r => Number(r.worked_hours || 0) > 0).sort((a,b)=>Number(a.efficiency_worked || 0)-Number(b.efficiency_worked || 0))[0]

  function money(value){
    const n = Number(value || 0)
    return n.toLocaleString(undefined, { style:'currency', currency:'USD', maximumFractionDigits:0 })
  }

  function pct(value){
    const n = Number(value || 0)
    return `${n.toFixed(1)}%`
  }

  function hours(value){
    const n = Number(value || 0)
    return n.toFixed(1)
  }

  function effClass(value){
    const n = Number(value || 0)
    if(n >= 100) return 'green'
    if(n >= 75) return 'orange'
    return 'red'
  }


  function gainLossText(row){
    const gain = Number(row.revenue_gain_worked || 0)
    const loss = Number(row.opportunity_loss_worked || 0)
    if(gain > 0) return `Gain ${money(gain)}`
    if(loss > 0) return `Loss ${money(loss)}`
    return money(0)
  }

  function gainLossClass(row){
    const gain = Number(row.revenue_gain_worked || 0)
    const loss = Number(row.opportunity_loss_worked || 0)
    if(gain > 0) return 'green'
    if(loss > 0) return 'red'
    return ''
  }

  function guaranteeDisplay(row){
    return Number(row.guarantee_hours || 0) > 0 ? hours(row.guarantee_hours) : '—'
  }

  function guaranteeEffDisplay(row){
    return row.efficiency_guarantee === null || row.efficiency_guarantee === undefined ? '—' : pct(row.efficiency_guarantee)
  }

  return (
    <div className="tech-efficiency-page">
      <div className="panel-head standalone-head">
        <div>
          <div className="panel-title"><Activity size={18}/> Tech Efficiency</div>
          <div className="small">Service Director view only. Labor rate set at $200/hr. Shows efficiency by worked hours and guarantee hours.</div>
        </div>
      </div>

      <div className="tech-efficiency-card-grid">
        <div className="tech-eff-card"><span>Shop Eff. Worked</span><b className={effClass(shopEfficiencyWorked)}>{pct(shopEfficiencyWorked)}</b><small>{hours(totalProduced)} produced / {hours(totalWorked)} worked</small></div>
        <div className="tech-eff-card"><span>Shop Eff. Tracked</span><b className={effClass(shopEfficiencyTracked)}>{pct(shopEfficiencyTracked)}</b><small>{hours(totalProduced)} produced / {hours(totalTrackedTarget)} tracked target</small></div>
        <div className="tech-eff-card"><span>Revenue Produced</span><b className="green">{money(totalRevenue)}</b><small>@ $200/hr</small></div>
        <div className="tech-eff-card"><span>Gain / Loss</span><b className={totalGainWorked > 0 ? 'green' : totalLossWorked > 0 ? 'red' : 'green'}>{totalGainWorked > 0 ? `Gain ${money(totalGainWorked)}` : totalLossWorked > 0 ? `Loss ${money(totalLossWorked)}` : money(0)}</b><small>Labor rate vs tracked target</small></div>
        <div className="tech-eff-card"><span>Top Tech</span><b className="green">{topTech?.tech_name ?? '—'}</b><small>{topTech ? pct(topTech.efficiency_worked) : '—'}</small></div>
        <div className="tech-eff-card"><span>Needs Coaching</span><b className="orange">{lowTech?.tech_name ?? '—'}</b><small>{lowTech ? pct(lowTech.efficiency_worked) : '—'}</small></div>
        <div className="tech-eff-card"><span>Above 100%</span><b className="green">{above100}</b><small>Techs producing over worked hours</small></div>
        <div className="tech-eff-card"><span>Below 75%</span><b className="red">{below75}</b><small>Coaching focus</small></div>
      </div>

      <div className="panel tech-efficiency-panel">
        <div className="panel-head">
          <div>
            <div className="panel-title">Technician Ranking</div>
            <div className="small">Gain/loss uses $200 labor rate against tracked target. Payroll loss uses employee rate and shortage to guarantee/worked target.</div>
          </div>
        </div>

        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Rank</th>
                <th>Technician</th>
                <th>Tech #</th>
                <th>Produced</th>
                <th>Worked</th>
                <th>Guarantee</th>
                <th>Eff. Worked</th>
                <th>Eff. Guarantee</th>
                <th>Revenue</th>
                <th>Gain / Loss</th>
                <th>Payroll Loss</th>
                <th>Tracked Target</th>
              </tr>
            </thead>
            <tbody>
              {sortedRows.length === 0 ? (
                <tr><td colSpan="12" className="small">No Tech Hours report uploaded yet.</td></tr>
              ) : sortedRows.map((r,idx)=>(
                <tr key={`${r.tech_number}-${r.tech_name}`}>
                  <td>{idx + 1}</td>
                  <td><b>{r.tech_name}</b></td>
                  <td>{r.tech_number}</td>
                  <td>{hours(r.produced_hours)}</td>
                  <td>{hours(r.worked_hours)}</td>
                  <td>{guaranteeDisplay(r)}</td>
                  <td className={effClass(r.efficiency_worked)}><b>{pct(r.efficiency_worked)}</b></td>
                  <td className={r.efficiency_guarantee === null || r.efficiency_guarantee === undefined ? '' : effClass(r.efficiency_guarantee)}><b>{guaranteeEffDisplay(r)}</b></td>
                  <td className="green">{money(r.revenue_produced)}</td>
                  <td className={gainLossClass(r)}>{gainLossText(r)}</td>
                  <td className={Number(r.opportunity_loss_guarantee || 0) > 0 ? 'red' : ''}>{money(r.opportunity_loss_guarantee)}</td>
                  <td>{hours(r.tracked_target_hours)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <TechVideoPerformancePanel rows={videoRows} efficiencyRows={techRows}/>
    </div>
  )
}


function ServiceDirectorOverview({ stats = {}, advisors = [], metricsPerformance = [], programHealthMetrics = [], surveyResults = [], techEfficiencyMetrics = [], techVideoMetrics = [], records = [] }) {
  const safeMetrics = (Array.isArray(metricsPerformance) ? metricsPerformance : []).filter(r => isDashboardAdvisor(r.advisor))
  const safeProgramHealth = (Array.isArray(programHealthMetrics) ? programHealthMetrics : []).filter(r => isDashboardAdvisor(r.advisor))
  const safeSurveyResults = Array.isArray(surveyResults) ? surveyResults : []
  const safeTechRows = Array.isArray(techEfficiencyMetrics) ? techEfficiencyMetrics : []
  const safeVideoRows = Array.isArray(techVideoMetrics) ? techVideoMetrics : []
  const safeDispositionRows = Array.isArray(records) ? records : []

  const storeNps = Number(stats?.nps_score ?? stats?.store_nps ?? 0)
  const regionNps = Number(stats?.region_score ?? 0)
  const nationalNps = Number(stats?.national_score ?? 0)
  const totalSent = safeProgramHealth.reduce((sum,r)=>sum + Number(r.invitations_sent || 0), 0)
  const totalResponses = safeSurveyResults.filter(r => Number(r.likelihood_to_recommend ?? r.ksi ?? 0) > 0).length || safeProgramHealth.reduce((sum,r)=>sum + Number(r.survey_responses || 0), 0)
  const responseRate = totalSent ? (totalResponses / totalSent) * 100 : 0

  const bestAdvisor = [...safeMetrics].sort((a,b)=>Number(b.final_nps || 0)-Number(a.final_nps || 0))[0]
  const coachingAdvisor = [...safeMetrics].filter(r => Number(r.sample_size || 0) > 0).sort((a,b)=>Number(a.final_nps || 0)-Number(b.final_nps || 0))[0]

  const totalProduced = safeTechRows.reduce((sum,r)=>sum + Number(r.produced_hours || 0), 0)
  const totalWorked = safeTechRows.reduce((sum,r)=>sum + Number(r.worked_hours || 0), 0)
  const shopEfficiency = totalWorked ? (totalProduced / totalWorked) * 100 : 0
  const totalRevenue = safeTechRows.reduce((sum,r)=>sum + Number(r.revenue_produced || 0), 0)
  const totalLoss = safeTechRows.reduce((sum,r)=>sum + Number(r.opportunity_loss_worked || 0), 0)
  const topTech = [...safeTechRows].sort((a,b)=>Number(b.efficiency_worked || 0)-Number(a.efficiency_worked || 0))[0]
  const coachingTech = [...safeTechRows].filter(r => Number(r.worked_hours || 0) > 0).sort((a,b)=>Number(a.efficiency_worked || 0)-Number(b.efficiency_worked || 0))[0]

  const totalVideos = safeVideoRows.reduce((sum,r)=>sum + Number(r.videos || 0), 0)
  const avgVideoScore = safeVideoRows.length ? safeVideoRows.reduce((sum,r)=>sum + Number(r.avg_score || 0), 0) / safeVideoRows.length : 0
  const topVideoTech = [...safeVideoRows].sort((a,b)=>Number(b.avg_score || 0)-Number(a.avg_score || 0))[0]
  const videoCoachingTech = [...safeVideoRows].filter(r => Number(r.videos || 0) > 0).sort((a,b)=>Number(a.avg_score || 0)-Number(b.avg_score || 0))[0]

  const unresponsive = Number(stats?.unresponsive ?? 0)
  const issues = Number(stats?.issues ?? 0)
  const dispositionOnly = Number(stats?.disposition_only ?? stats?.surveyed_no_followup ?? 0)
  const openDisposition = safeDispositionRows.filter(r => {
    const status = String(r.survey_status || r.commitment || '').toLowerCase()
    return status && !status.includes('complete')
  }).length

  function money(value){ return Number(value || 0).toLocaleString(undefined, { style:'currency', currency:'USD', maximumFractionDigits:0 }) }
  function pct(value){ return `${Number(value || 0).toFixed(1)}%` }
  function npsColor(value){ const n=Number(value||0); return n>=83?'green':n>=70?'orange':'red' }
  function effColor(value){ const n=Number(value||0); return n>=100?'green':n>=75?'orange':'red' }
  function videoColor(value){ const n=Number(value||0); return n>=85?'green':n>=70?'orange':'red' }

  const coachingItems = [
    { title:'Advisor CSI Coaching', name: coachingAdvisor?.advisor ?? '—', metric: coachingAdvisor ? `${Number(coachingAdvisor.final_nps || 0).toFixed(1)} NPS` : '—', tone: npsColor(coachingAdvisor?.final_nps) },
    { title:'Tech Efficiency Coaching', name: coachingTech?.tech_name ?? '—', metric: coachingTech ? `${Number(coachingTech.efficiency_worked || 0).toFixed(1)}% Efficiency` : '—', tone: effColor(coachingTech?.efficiency_worked) },
    { title:'Video Coaching', name: videoCoachingTech?.tech_name ?? '—', metric: videoCoachingTech ? `${Number(videoCoachingTech.avg_score || 0).toFixed(1)} Avg Score` : '—', tone: videoColor(videoCoachingTech?.avg_score) },
    { title:'Disposition Focus', name:'Open / Unresponsive', metric:`${openDisposition || unresponsive || 0} items`, tone:(openDisposition || unresponsive) > 0 ? 'orange' : 'green' },
  ]

  return (
    <div className="service-director-overview">
      <div className="director-hero">
        <div>
          <div className="eyebrow">Service Director Dashboard</div>
          <h1>Daily Store Health</h1>
          <p>CSI, advisor performance, technician efficiency, video quality, and coaching opportunities in one view.</p>
        </div>
        <div className="director-date">Live Dashboard</div>
      </div>

      <div className="director-kpi-grid">
        <div className="director-kpi"><span>Store NPS</span><b className={npsColor(storeNps)}>{storeNps.toFixed(2)}</b><small>Region {regionNps.toFixed(2)} / National {nationalNps.toFixed(2)}</small></div>
        <div className="director-kpi"><span>Survey Response</span><b className={responseRate >= 15 ? 'green' : responseRate >= 8 ? 'orange' : 'red'}>{pct(responseRate)}</b><small>{totalResponses} responses / {totalSent} sent</small></div>
        <div className="director-kpi"><span>Shop Efficiency</span><b className={effColor(shopEfficiency)}>{pct(shopEfficiency)}</b><small>{totalProduced.toFixed(1)} produced / {totalWorked.toFixed(1)} worked</small></div>
        <div className="director-kpi"><span>Revenue Produced</span><b className="green">{money(totalRevenue)}</b><small>@ $200/hr</small></div>
        <div className="director-kpi"><span>Opportunity Loss</span><b className={totalLoss > 0 ? 'red' : 'green'}>{money(totalLoss)}</b><small>Against tracked target</small></div>
        <div className="director-kpi"><span>Video Score</span><b className={videoColor(avgVideoScore)}>{avgVideoScore.toFixed(1)}</b><small>{totalVideos} total videos</small></div>
      </div>

      <div className="director-panels">
        <div className="panel director-panel">
          <div className="panel-head"><div><div className="panel-title"><Trophy size={17}/> Top Performers</div><div className="small">Best current performers by category.</div></div></div>
          <div className="director-list">
            <div><span>Advisor CSI</span><b>{bestAdvisor?.advisor ?? '—'}</b><em className={npsColor(bestAdvisor?.final_nps)}>{bestAdvisor ? Number(bestAdvisor.final_nps || 0).toFixed(1) : '—'} NPS</em></div>
            <div><span>Tech Efficiency</span><b>{topTech?.tech_name ?? '—'}</b><em className={effColor(topTech?.efficiency_worked)}>{topTech ? pct(topTech.efficiency_worked) : '—'}</em></div>
            <div><span>Video Quality</span><b>{topVideoTech?.tech_name ?? '—'}</b><em className={videoColor(topVideoTech?.avg_score)}>{topVideoTech ? Number(topVideoTech.avg_score || 0).toFixed(1) : '—'} Score</em></div>
          </div>
        </div>

        <div className="panel director-panel">
          <div className="panel-head"><div><div className="panel-title"><AlertTriangle size={17}/> Coaching Opportunities</div><div className="small">Where attention should go first.</div></div></div>
          <div className="coaching-grid">
            {coachingItems.map(item => (
              <div className="coaching-card" key={item.title}>
                <span>{item.title}</span><b>{item.name}</b><em className={item.tone}>{item.metric}</em>
              </div>
            ))}
          </div>
        </div>

        <div className="panel director-panel">
          <div className="panel-head"><div><div className="panel-title"><ClipboardList size={17}/> Disposition Health</div><div className="small">Survey follow-up workload snapshot.</div></div></div>
          <div className="director-mini-grid">
            <div><span>Disposition Only</span><b>{dispositionOnly}</b></div>
            <div><span>Unresponsive</span><b className={unresponsive > 0 ? 'red' : 'green'}>{unresponsive}</b></div>
            <div><span>Issues</span><b className={issues > 0 ? 'red' : 'green'}>{issues}</b></div>
            <div><span>Open Items</span><b className={openDisposition > 0 ? 'orange' : 'green'}>{openDisposition}</b></div>
          </div>
        </div>

        <div className="panel director-panel">
          <div className="panel-head"><div><div className="panel-title"><Upload size={17}/> Upload Checklist</div><div className="small">Recommended order for clean dashboard updates.</div></div></div>
          <ol className="director-upload-list">
            <li>CSI Report</li><li>Disposition Report</li><li>Survey Results</li><li>Metrics Performance</li><li>Program Health</li><li>Tech Efficiency</li><li>Tech Video Report</li><li>CDK Workbook</li><li>Advisor Performance</li>
          </ol>
        </div>
      </div>
    </div>
  )
}

function IsolatedCsiPerformanceView({ stats = {}, advisors = [], metricsPerformance = [], programHealthMetrics = [], surveyResults = [], user }) {
  const safeAdvisors = managerVisibleAdvisorRows(advisors, user)
  const visibleMetricsPerformance = (Array.isArray(metricsPerformance) ? metricsPerformance : []).filter(r => user?.role === 'advisor' ? isSameAdvisorName(r.advisor, user.advisor) : isDashboardAdvisor(r.advisor))
  const visibleProgramHealthMetrics = (Array.isArray(programHealthMetrics) ? programHealthMetrics : []).filter(r => user?.role === 'advisor' ? isSameAdvisorName(r.advisor, user.advisor) : isDashboardAdvisor(r.advisor))
  const store = Number(stats?.nps_score ?? 0)
  const region = Number(stats?.region_score ?? 0)
  const national = Number(stats?.national_score ?? 0)
  const completed = Number(stats?.complete ?? 0)
  const committed = Number(stats?.committed ?? 0)
  const issues = Number(stats?.issues ?? 0)
  const total = Number(stats?.followup_total ?? 0)
  const completedPct = total ? ((completed / total) * 100).toFixed(1) : '0.0'
  const committedPct = total ? ((committed / total) * 100).toFixed(1) : '0.0'

  const csiCards = [
    ['Store NPS', store.toFixed(2), store >= 83 ? 'green' : store >= 70 ? 'orange' : 'red'],
    ['Region', region.toFixed(2), 'blue'],
    ['National', national.toFixed(2), 'purple'],
    ['Completed %', `${completedPct}%`, Number(completedPct) >= 80 ? 'green' : 'orange'],
    ['Committed %', `${committedPct}%`, 'blue'],
    ['Issues', issues, issues > 0 ? 'red' : 'green'],
  ]

  return (
    <div className="csi-performance-page">
      <div className="csi-gauge-grid">
        {csiCards.map(([label, value, tone]) => (
          <div className="gauge-card" key={label}>
            <div className="gauge-title">{label}</div>
            <div className={`gauge-ring ${tone}`} style={{'--pct':'70%'}}>
              <div className="gauge-inner">
                <div className={`gauge-value ${tone}`}>{value}</div>
                <div className="gauge-sub">Current</div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <AdvisorCsiScorecard programHealthMetrics={programHealthMetrics} surveyResults={surveyResults} metricsPerformance={metricsPerformance} user={user}/>

      <div className="panel">
        <div className="panel-head">
          <div>
            <div className="panel-title">Advisor CSI Rankings</div>
            <div className="small">CSI Performance view only. Use Advisor Rankings tab for drill-downs.</div>
          </div>
        </div>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Advisor</th>
                <th>NPS / CSI</th>
                <th>Completed</th>
                <th>Committed</th>
                <th>Unresponsive</th>
                <th>Issues</th>
              </tr>
            </thead>
            <tbody>
              {safeAdvisors.map((a) => (
                <tr key={a.advisor}>
                  <td><button className="advisor-link" onClick={()=>onAdvisorClick?.(a)}>{a.advisor}</button></td>
                  <td className={Number(a.nps_score || 0) >= 83 ? 'green' : Number(a.nps_score || 0) >= 70 ? 'orange' : 'red'}>
                    {Number(a.nps_score || 0).toFixed(2)}
                  </td>
                  <td>{a.completed_surveys ?? 0}</td>
                  <td>{a.committed ?? 0}</td>
                  <td>{a.unresponsive ?? 0}</td>
                  <td>{a.issues ?? 0}</td>
                </tr>
              ))}
              {safeAdvisors.length === 0 && (
                <tr><td colSpan="6" className="small">No advisor CSI data loaded yet.</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <AdvisorMetricsPerformanceTable rows={visibleMetricsPerformance}/>
      <ProgramHealthTable rows={visibleProgramHealthMetrics}/>
    </div>
  )
}



function advisorAlias(value){
  const raw = titleCaseAdvisor(value)
  const key = raw.toLowerCase()
  const map = {
    toren: 'Toren Hamilton',
    liam: 'Liam Weisbrodt',
    lane: 'Lane Depriest',
    stanley: 'Stanley Snyder',
    garrett: 'Garrett Willey',
    morgan: 'Morgan Farrell',
    billy: 'Billy Greenhaw',
  }
  return map[key] || raw
}

function parseRentalDays(value){
  if(value === null || value === undefined || value === '') return null
  if(String(value).toLowerCase().includes('today')) return 0
  const n = Number(value)
  return Number.isFinite(n) ? n : null
}


function cleanCurrencyNumber(value){
  if(value === null || value === undefined || value === '') return null
  const n = Number(String(value).replace(/[$,% ,]/g,'').trim())
  return Number.isFinite(n) ? n : null
}

function salesAdvisorName(value){
  let raw = String(value || '').trim()
  if(raw.includes(',')){
    const [last, first] = raw.split(',').map(x=>x.trim()).filter(Boolean)
    if(first && last) raw = `${first} ${last}`
  }
  raw = raw.replace(/\bStan\b/i, 'Stanley')
  return titleCaseAdvisor(raw)
}

function getSheetCellValue(workbook, sheetName, cell){
  const ws = workbook.Sheets[sheetName]
  return ws?.[cell]?.v ?? ws?.[cell]?.w ?? null
}

function parseUsDate(value){
  const raw = String(value || '').trim()
  const match = raw.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/)
  if(!match) return null
  const [,m,d,y] = match
  return new Date(Number(y), Number(m)-1, Number(d))
}

function countWorkingDaysMonSat(startDate, endDate){
  if(!startDate || !endDate) return 0
  const d = new Date(startDate)
  let count = 0
  while(d <= endDate){
    if(d.getDay() !== 0) count += 1 // Sunday excluded. Saturdays count.
    d.setDate(d.getDate()+1)
  }
  return count
}

function getWorkingDaysCompletedFromMtdTitle(workbook, sheetName){
  const title = String(getSheetCellValue(workbook, sheetName, 'A1') || '')
  const matches = title.match(/(\d{1,2}\/\d{1,2}\/\d{4})\s*-\s*(\d{1,2}\/\d{1,2}\/\d{4})/)
  if(!matches) return 0
  return countWorkingDaysMonSat(parseUsDate(matches[1]), parseUsDate(matches[2]))
}

function getProjectionWorkingDays(workbook){
  const total = cleanCurrencyNumber(getSheetCellValue(workbook, 'June Projection', 'B2')) || 26
  const completedFromDates = getWorkingDaysCompletedFromMtdTitle(workbook, 'June MTD')
  const completedFromSheet = cleanCurrencyNumber(getSheetCellValue(workbook, 'June Projection', 'B3')) || 0
  const completed = completedFromDates || completedFromSheet || 1
  return { total, completed, factor: completed ? total / completed : 1 }
}


function paceCell(workbook, cell){
  const ws = workbook.Sheets['Pace'] || workbook.Sheets[workbook.SheetNames[0]]
  const raw = ws?.[cell]?.v ?? ws?.[cell]?.w ?? null
  if(raw === null || raw === undefined || raw === '') return null
  if(typeof raw === 'number') return raw
  const cleaned = String(raw).replace(/[$,%]/g,'').trim()
  const n = Number(cleaned)
  return Number.isFinite(n) ? n : raw
}

function paceMetric(metric_key, metric_label, value, section='Fixed Operations'){
  const n = typeof value === 'number' ? value : Number(value)
  return {
    metric_key,
    metric_label,
    metric_value: Number.isFinite(n) ? n : null,
    metric_display: value == null ? '' : String(value),
    section
  }
}

