function paceValue(rows, key){
  const row = (rows || []).find(r => r.metric_key === key)
  return Number(row?.metric_value || 0)
}

function parseAdvisorSalesSheet(workbook, sheetName, monthLabel){
  const ws = workbook.Sheets[sheetName]
  if(!ws) return []
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })
  return rows.map((r)=>({
    month_label: monthLabel,
    advisor: salesAdvisorName(r['Advisor']),
    ros: cleanCurrencyNumber(r['Total ROs'] ?? r['ROs']),
    sold_hours: cleanCurrencyNumber(r['Total Sold Hrs'] ?? r['Sold Hrs']),
    warranty_gp: cleanCurrencyNumber(r['Warranty Net GP $'] ?? r['Warr GP']),
    parts_gp: cleanCurrencyNumber(r['Parts GP']),
    total_warranty_gp: cleanCurrencyNumber(r['Warranty Net GP $'] ?? r['Tot Warr GP']),
    labor_gp_percent: cleanCurrencyNumber(r['Labor GP%']),
    parts_gp_percent: cleanCurrencyNumber(r['Parts GP%']),
    gp_percent: cleanCurrencyNumber(r['Total GP %'] ?? r['GP%']),
    customer_pay_gp: cleanCurrencyNumber(r['CP Net GP $'] ?? r['GP$'] ?? r['GPcpV$']),
    elr: cleanCurrencyNumber(r['Net ELR'] ?? r['ELR']),
    avg_cp_hours_ro: cleanCurrencyNumber(r['Avg CP Hrs/RO']),
    avg_hours_ro: cleanCurrencyNumber(r['Avg Hrs/RO']),
  })).filter(r => r.advisor && r.ros !== null)
}

