    parts_gross: 0,
    cp_labor_gross: 0,
    cp_parts_gross: 0,
    warranty_labor_gross: 0,
    warranty_parts_gross: 0,
    internal_labor_gross: 0,
    internal_parts_gross: 0,
    customer_pay_gp: 0,
