function mergeAdvisorSalesRows(rows = [], monthLabel = 'June MTD'){
  const map = new Map(DASHBOARD_ADVISORS.map(advisor => [normalizeAdvisorMatchName(advisor), emptyAdvisorSalesRow(advisor, monthLabel)]))

  ;(rows || []).forEach(row => {
    const advisor = activeAdvisorIdMap(row.advisor) || activeAdvisorName(row.advisor) || salesAdvisorName(row.advisor)
    if(!isDashboardAdvisor(advisor)) return
    const key = normalizeAdvisorMatchName(advisor)
    const acc = map.get(key) || emptyAdvisorSalesRow(advisor, monthLabel)
    acc.ros += Number(row.ros || row.total_ros || row.cp_ros || 0)
    acc.total_ros = acc.ros
    acc.cp_ros += Number(row.cp_ros || 0)
    acc.warranty_ros += Number(row.warranty_ros || 0)
    acc.internal_ros += Number(row.internal_ros || 0)
    acc.sold_hours += Number(row.sold_hours || 0)
    acc.cp_sold_hours += Number(row.cp_sold_hours || (row.customer_pay_gp || row.cp_gross ? row.sold_hours : 0) || 0)
    acc.warranty_sold_hours += Number(row.warranty_sold_hours || (row.warranty_gp || row.warranty_gross || row.total_warranty_gp ? row.sold_hours : 0) || 0)
    acc.internal_sold_hours += Number(row.internal_sold_hours || (row.internal_gross || row.total_internal_gp ? row.sold_hours : 0) || 0)
    acc.labor_sales += Number(row.labor_sales || 0)
    acc.cp_labor_sales += Number(row.cp_labor_sales || (row.customer_pay_gp || row.cp_gross ? row.labor_sales : 0) || 0)
    acc.warranty_labor_sales += Number(row.warranty_labor_sales || (row.warranty_gp || row.warranty_gross || row.total_warranty_gp ? row.labor_sales : 0) || 0)
    acc.internal_labor_sales += Number(row.internal_labor_sales || (row.internal_gross || row.total_internal_gp ? row.labor_sales : 0) || 0)
    acc.parts_sales = Number(acc.parts_sales || 0) + Number(row.parts_sales || 0)

    const rowCpGross = Number(row.customer_pay_gp || row.cp_gross || 0)
    const rowWarrantyGross = Number(row.warranty_gp || row.warranty_gross || row.total_warranty_gp || 0)
    const rowInternalGross = Number(row.internal_gross || row.total_internal_gp || 0)
    const rowPartsGross = Number(row.parts_gross || row.parts_gp || 0)
    const rowLaborGross = Number(row.labor_gross || 0) || Math.max(0, Number(row.total_gross || 0) - rowPartsGross)

    acc.customer_pay_gp += rowCpGross
    acc.cp_gross = acc.customer_pay_gp
    acc.warranty_gp += rowWarrantyGross
    acc.warranty_gross = acc.warranty_gp
    acc.total_warranty_gp = acc.warranty_gp
    acc.internal_gross += rowInternalGross
    acc.total_internal_gp = acc.internal_gross

    acc.cp_labor_gross += Number(row.cp_labor_gross || (rowCpGross ? Math.max(0, rowCpGross - Number(row.cp_parts_gross || rowPartsGross || 0)) : 0) || 0)
    acc.cp_parts_gross += Number(row.cp_parts_gross || (rowCpGross ? rowPartsGross : 0) || 0)
    acc.warranty_labor_gross += Number(row.warranty_labor_gross || (rowWarrantyGross ? Math.max(0, rowWarrantyGross - Number(row.warranty_parts_gross || rowPartsGross || 0)) : 0) || 0)
    acc.warranty_parts_gross += Number(row.warranty_parts_gross || (rowWarrantyGross ? rowPartsGross : 0) || 0)
    acc.internal_labor_gross += Number(row.internal_labor_gross || (rowInternalGross ? Math.max(0, rowInternalGross - Number(row.internal_parts_gross || rowPartsGross || 0)) : 0) || 0)
    acc.internal_parts_gross += Number(row.internal_parts_gross || (rowInternalGross ? rowPartsGross : 0) || 0)
    acc.labor_gross += rowLaborGross
    acc.parts_gross += rowPartsGross
    acc.parts_gp += Number(row.parts_gp || rowPartsGross || 0)
    acc.total_gross = acc.customer_pay_gp + acc.total_warranty_gp + acc.total_internal_gp
    acc.month_label = monthLabel
    map.set(key, acc)
  })

  return [...map.values()].map(row => {
    row.elr = row.sold_hours ? row.labor_sales / row.sold_hours : 0
    row.net_elr = row.elr
    row.gp_percent = (row.labor_sales + row.parts_sales) ? (row.customer_pay_gp / (row.labor_sales + row.parts_sales)) * 100 : 0
    row.labor_gp_percent = row.labor_sales ? (row.labor_gross / row.labor_sales) * 100 : 0
    row.parts_gp_percent = row.parts_sales ? (row.parts_gross / row.parts_sales) * 100 : 0
    row.avg_cp_hours_ro = row.ros ? row.sold_hours / row.ros : 0
    row.avg_hours_ro = row.avg_cp_hours_ro
    row.projected_ros = row.projected_ros || row.ros
    row.projected_sold_hours = row.projected_sold_hours || row.sold_hours
    row.projected_cp_labor_gross = row.projected_cp_labor_gross || row.cp_labor_gross
    row.projected_cp_parts_gross = row.projected_cp_parts_gross || row.cp_parts_gross
    row.projected_warranty_labor_gross = row.projected_warranty_labor_gross || row.warranty_labor_gross
    row.projected_warranty_parts_gross = row.projected_warranty_parts_gross || row.warranty_parts_gross
    row.projected_internal_labor_gross = row.projected_internal_labor_gross || row.internal_labor_gross
    row.projected_internal_parts_gross = row.projected_internal_parts_gross || row.internal_parts_gross
    row.projected_customer_pay_gp = row.projected_customer_pay_gp || row.customer_pay_gp
    row.projected_cp_gross = row.projected_customer_pay_gp
    row.projected_total_warranty_gp = row.projected_total_warranty_gp || row.total_warranty_gp
    row.projected_warranty_gp = row.projected_total_warranty_gp
    row.projected_warranty_gross = row.projected_total_warranty_gp
    row.projected_total_internal_gp = row.projected_total_internal_gp || row.total_internal_gp
    row.projected_internal_gross = row.projected_total_internal_gp
    row.projected_total_gross = row.projected_customer_pay_gp + row.projected_total_warranty_gp + row.projected_total_internal_gp
    return row
  })
}


function parseRepairOrderAnalysisCategoryTotals(workbook, monthLabel = 'June MTD', category = 'cp'){
  const ws = workbook.Sheets['Repair Order Analysis'] || workbook.Sheets[workbook.SheetNames[0]]
  if(!ws) return []
  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  const rows = []

  function rowTotals(r){
    const ros = cleanCurrencyNumber(r?.[2]) || 0
    const laborSales = cleanCurrencyNumber(r?.[3]) || 0
    const laborGross = cleanCurrencyNumber(r?.[5]) || 0
    const soldHours = cleanCurrencyNumber(r?.[10]) || 0
    const partsSales = cleanCurrencyNumber(r?.[12]) || 0
    const partsGross = cleanCurrencyNumber(r?.[14]) || 0
    const totalSales = cleanCurrencyNumber(r?.[18]) || laborSales + partsSales
    const totalGrossValue = cleanCurrencyNumber(r?.[20]) || laborGross + partsGross
    return { ros, laborSales, laborGross, soldHours, partsSales, partsGross, totalSales, totalGrossValue }
  }

  raw.forEach(r => {
    const first = String(r?.[0] || '').trim().toLowerCase()
    const advisorNumber = String(r?.[1] || '').trim()
    const advisor = activeAdvisorIdMap(advisorNumber)
    if(first !== 'total' || !advisor) return

    const totals = rowTotals(r)
    const base = {
      month_label: monthLabel,
      advisor,
      ros: totals.ros,
      total_ros: totals.ros,
      cp_ros: category === 'cp' ? totals.ros : 0,
      warranty_ros: category === 'warranty' ? totals.ros : 0,
      internal_ros: category === 'internal' ? totals.ros : 0,
      sold_hours: totals.soldHours,
      cp_sold_hours: category === 'cp' ? totals.soldHours : 0,
      warranty_sold_hours: category === 'warranty' ? totals.soldHours : 0,
      internal_sold_hours: category === 'internal' ? totals.soldHours : 0,
      labor_sales: totals.laborSales,
      cp_labor_sales: category === 'cp' ? totals.laborSales : 0,
      warranty_labor_sales: category === 'warranty' ? totals.laborSales : 0,
      internal_labor_sales: category === 'internal' ? totals.laborSales : 0,
      parts_sales: totals.partsSales,
      labor_gross: totals.laborGross,
      parts_gross: totals.partsGross,
      cp_labor_gross: category === 'cp' ? totals.laborGross : 0,
      cp_parts_gross: category === 'cp' ? totals.partsGross : 0,
      warranty_labor_gross: category === 'warranty' ? totals.laborGross : 0,
      warranty_parts_gross: category === 'warranty' ? totals.partsGross : 0,
      internal_labor_gross: category === 'internal' ? totals.laborGross : 0,
      internal_parts_gross: category === 'internal' ? totals.partsGross : 0,
      customer_pay_gp: 0,
      cp_gross: 0,
      warranty_gp: 0,
      warranty_gross: 0,
      total_warranty_gp: 0,
      internal_gross: 0,
      total_internal_gp: 0,
      total_gross: totals.totalGrossValue,
      parts_gp: totals.partsGross,
      elr: totals.soldHours ? totals.laborSales / totals.soldHours : (cleanCurrencyNumber(r?.[11]) || 0),
      net_elr: totals.soldHours ? totals.laborSales / totals.soldHours : (cleanCurrencyNumber(r?.[11]) || 0),
      gp_percent: totals.totalSales ? (totals.totalGrossValue / totals.totalSales) * 100 : 0,
      labor_gp_percent: totals.laborSales ? (totals.laborGross / totals.laborSales) * 100 : 0,
      parts_gp_percent: totals.partsSales ? (totals.partsGross / totals.partsSales) * 100 : 0,
      avg_cp_hours_ro: totals.ros ? totals.soldHours / totals.ros : 0,
      avg_hours_ro: totals.ros ? totals.soldHours / totals.ros : 0,
    }

    if(category === 'warranty'){
      base.warranty_gp = totals.totalGrossValue
      base.warranty_gross = totals.totalGrossValue
      base.total_warranty_gp = totals.totalGrossValue
      base.customer_pay_gp = 0
      base.cp_gross = 0
    } else if(category === 'internal'){
      base.internal_gross = totals.totalGrossValue
      base.total_internal_gp = totals.totalGrossValue
      base.customer_pay_gp = 0
      base.cp_gross = 0
    } else {
      base.customer_pay_gp = totals.totalGrossValue
      base.cp_gross = totals.totalGrossValue
    }

    rows.push(base)
  })

  return mergeAdvisorSalesRows(rows, monthLabel)
}

function parseRepairOrderAnalysisTotals(workbook, monthLabel = 'June MTD'){
  const ws = workbook.Sheets['Repair Order Analysis'] || workbook.Sheets[workbook.SheetNames[0]]
  if(!ws) return []
  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  const rows = []
  const salesCategories = new Set(['competitive','maintenance','repair'])

  function categoryName(value){
    return String(value || '').trim().toLowerCase()
  }

  function rowTotals(r){
    const ros = cleanCurrencyNumber(r?.[2]) || 0
    const laborSales = cleanCurrencyNumber(r?.[3]) || 0
    const laborGross = cleanCurrencyNumber(r?.[5]) || 0
    const soldHours = cleanCurrencyNumber(r?.[10]) || 0
    const partsSales = cleanCurrencyNumber(r?.[12]) || 0
    const partsGross = cleanCurrencyNumber(r?.[14]) || 0
    const totalSales = cleanCurrencyNumber(r?.[18]) || laborSales + partsSales
    const totalGrossValue = cleanCurrencyNumber(r?.[20]) || laborGross + partsGross
    return { ros, laborSales, laborGross, soldHours, partsSales, partsGross, totalSales, totalGrossValue }
  }

  for(let i = 0; i < raw.length; i++){
    const r = raw[i]
    const first = String(r?.[0] || '').trim().toLowerCase()
    const advisorNumber = String(r?.[1] || '').trim()
    const advisor = activeAdvisorIdMap(advisorNumber)
    if(first !== 'total' || !advisor) continue

    const grand = rowTotals(r)
    const bucket = {
      customerPay: { ros:0, laborSales:0, laborGross:0, soldHours:0, partsSales:0, partsGross:0, totalSales:0, totalGrossValue:0 },
      warranty: { ros:0, laborSales:0, laborGross:0, soldHours:0, partsSales:0, partsGross:0, totalSales:0, totalGrossValue:0 },
      internal: { ros:0, laborSales:0, laborGross:0, soldHours:0, partsSales:0, partsGross:0, totalSales:0, totalGrossValue:0 },
    }

    // In the CDK Repair Order Analysis export, each advisor total is followed by
    // summary lines for Competitive, Maintenance, Repair, Internal, and Warranty.
    // Use those lines so CP gross and Warranty gross stay separate.
    for(let j = i + 1; j < raw.length; j++){
      const rr = raw[j]
      const nextFirst = String(rr?.[0] || '').trim().toLowerCase()
      const label = categoryName(rr?.[1])
      if(nextFirst === 'total') break
      if(!['competitive','maintenance','repair','internal','warranty'].includes(label)) continue
      const totals = rowTotals(rr)
      const target = label === 'warranty' ? bucket.warranty : label === 'internal' ? bucket.internal : bucket.customerPay
      Object.keys(target).forEach(k => { target[k] += Number(totals[k] || 0) })
    }

    const cp = bucket.customerPay.totalGrossValue || grand.totalGrossValue
    const warranty = bucket.warranty.totalGrossValue || 0
    const cpSales = bucket.customerPay.totalSales || grand.totalSales
    const cpLaborSales = bucket.customerPay.laborSales || grand.laborSales
    const cpPartsSales = bucket.customerPay.partsSales || grand.partsSales
    const cpPartsGross = bucket.customerPay.partsGross || grand.partsGross
    const cpSoldHours = bucket.customerPay.soldHours || grand.soldHours
    const cpRos = bucket.customerPay.ros || grand.ros

    rows.push({
      month_label: monthLabel,
      advisor,
      ros: cpRos + (bucket.warranty.ros || 0) + (bucket.internal.ros || 0),
      total_ros: cpRos + (bucket.warranty.ros || 0) + (bucket.internal.ros || 0),
      cp_ros: cpRos,
      warranty_ros: bucket.warranty.ros || 0,
      internal_ros: bucket.internal.ros || 0,
      sold_hours: cpSoldHours + (bucket.warranty.soldHours || 0) + (bucket.internal.soldHours || 0),
      cp_sold_hours: cpSoldHours,
      warranty_sold_hours: bucket.warranty.soldHours || 0,
      internal_sold_hours: bucket.internal.soldHours || 0,
      labor_sales: cpLaborSales + (bucket.warranty.laborSales || 0) + (bucket.internal.laborSales || 0),
      cp_labor_sales: cpLaborSales,
      warranty_labor_sales: bucket.warranty.laborSales || 0,
      internal_labor_sales: bucket.internal.laborSales || 0,
      parts_sales: cpPartsSales + (bucket.warranty.partsSales || 0) + (bucket.internal.partsSales || 0),
      labor_gross: bucket.customerPay.laborGross + bucket.warranty.laborGross + bucket.internal.laborGross,
      parts_gross: bucket.customerPay.partsGross + bucket.warranty.partsGross + bucket.internal.partsGross,
      cp_labor_gross: bucket.customerPay.laborGross || Math.max(0, cp - cpPartsGross),
      cp_parts_gross: cpPartsGross,
      warranty_labor_gross: bucket.warranty.laborGross || Math.max(0, warranty - Number(bucket.warranty.partsGross || 0)),
      warranty_parts_gross: bucket.warranty.partsGross || 0,
      internal_labor_gross: bucket.internal.laborGross || 0,
      internal_parts_gross: bucket.internal.partsGross || 0,
      customer_pay_gp: cp,
      cp_gross: cp,
      warranty_gp: warranty,
      warranty_gross: warranty,
      total_warranty_gp: warranty,
      internal_gross: bucket.internal.totalGrossValue || 0,
      total_internal_gp: bucket.internal.totalGrossValue || 0,
      total_gross: cp + warranty + (bucket.internal.totalGrossValue || 0),
      parts_gp: cpPartsGross + (bucket.warranty.partsGross || 0) + (bucket.internal.partsGross || 0),
      elr: cpSoldHours ? cpLaborSales / cpSoldHours : (cleanCurrencyNumber(r?.[11]) || 0),
      net_elr: cpSoldHours ? cpLaborSales / cpSoldHours : (cleanCurrencyNumber(r?.[11]) || 0),
      gp_percent: cpSales ? (cp / cpSales) * 100 : 0,
      labor_gp_percent: cpLaborSales ? ((cp - cpPartsGross) / cpLaborSales) * 100 : 0,
      parts_gp_percent: cpPartsSales ? (cpPartsGross / cpPartsSales) * 100 : 0,
      avg_cp_hours_ro: cpRos ? cpSoldHours / cpRos : 0,
      avg_hours_ro: cpRos ? cpSoldHours / cpRos : 0,
    })
  }

  return mergeAdvisorSalesRows(rows, monthLabel)
}



function advisorProjectionPace(){
  // Napleton service department is normally open Monday-Saturday.
  // Projection uses remaining selling days in the current month, including today,
  // so if today plus 3 more selling days remain, projected numbers continue to climb.
  const now = new Date()
  const year = now.getFullYear()
  const month = now.getMonth()
  const lastDay = new Date(year, month + 1, 0).getDate()
  const isSellingDay = (date) => date.getDay() !== 0
  let totalSellingDays = 0
  let remainingSellingDays = 0
  for(let day = 1; day <= lastDay; day += 1){
    const d = new Date(year, month, day)
    if(!isSellingDay(d)) continue
    totalSellingDays += 1
    if(day >= now.getDate()) remainingSellingDays += 1
  }
  const elapsedSellingDays = Math.max(1, totalSellingDays - remainingSellingDays)
  const paceFactor = totalSellingDays > elapsedSellingDays ? totalSellingDays / elapsedSellingDays : 1
  return { totalSellingDays, remainingSellingDays, elapsedSellingDays, paceFactor }
}

function pacedProjectionValue(actualValue, openValue = 0, paceFactor = 1){
  return (Number(actualValue || 0) * Number(paceFactor || 1)) + Number(openValue || 0)
}

function applyOpenRosToProjections(currentRows = []){
  const { paceFactor, remainingSellingDays, totalSellingDays, elapsedSellingDays } = advisorProjectionPace()
  return currentRows.map(row => {
    const projectedRos = pacedProjectionValue(row.ros, 0, paceFactor)
    const projectedHours = pacedProjectionValue(row.sold_hours, 0, paceFactor)
    const projectedCpLabor = pacedProjectionValue(row.cp_labor_gross, 0, paceFactor)
    const projectedCpParts = pacedProjectionValue(row.cp_parts_gross, 0, paceFactor)
    const projectedWarrantyLabor = pacedProjectionValue(row.warranty_labor_gross, 0, paceFactor)
    const projectedWarrantyParts = pacedProjectionValue(row.warranty_parts_gross, 0, paceFactor)
    const projectedInternalLabor = pacedProjectionValue(row.internal_labor_gross, 0, paceFactor)
    const projectedInternalParts = pacedProjectionValue(row.internal_parts_gross, 0, paceFactor)
    const projectedCp = projectedCpLabor + projectedCpParts
    const projectedWarr = projectedWarrantyLabor + projectedWarrantyParts
    const projectedInternal = projectedInternalLabor + projectedInternalParts
    return {
      ...row,
      projection_remaining_days: remainingSellingDays,
      projection_total_days: totalSellingDays,
      projection_elapsed_days: elapsedSellingDays,
      projection_pace_factor: paceFactor,
      projected_ros: projectedRos,
      projected_sold_hours: projectedHours,
      projected_cp_labor_gross: projectedCpLabor,
      projected_cp_parts_gross: projectedCpParts,
      projected_warranty_labor_gross: projectedWarrantyLabor,
      projected_warranty_parts_gross: projectedWarrantyParts,
      projected_internal_labor_gross: projectedInternalLabor,
      projected_internal_parts_gross: projectedInternalParts,
      projected_customer_pay_gp: projectedCp,
      projected_cp_gross: projectedCp,
      projected_warranty_gp: projectedWarr,
      projected_warranty_gross: projectedWarr,
      projected_total_warranty_gp: projectedWarr,
      projected_internal_gross: projectedInternal,
      projected_total_internal_gp: projectedInternal,
      projected_total_gross: projectedCp + projectedWarr + projectedInternal,
    }
  })
}

function parseAdvisorSalesFiles(fileWorkbooks = []){
  const currentBuckets = { cp: [], warranty: [], internal: [] }
  const lastBuckets = { cp: [], warranty: [], internal: [] }
  let currentRows = []
  let lastRows = []
  let fallbackRows = []

  const appendBucket = (target, category, rows) => {
    if(!rows?.length) return
    target[category] = [...(target[category] || []), ...rows]
  }

  fileWorkbooks.forEach(({name, workbook}) => {
    const fileName = String(name || '').toLowerCase()
    const hasRoAnalysis = !!(workbook.Sheets['Repair Order Analysis'])

    if(hasRoAnalysis){
      const isLast = fileName.includes('may') || fileName.includes('last') || fileName.includes('previous')
      const monthLabel = isLast ? 'May MTD' : 'June MTD'
      const category = fileName.includes('war') || fileName.includes('warr') ? 'warranty'
        : fileName.includes('int') || fileName.includes('internal') ? 'internal'
        : 'cp'

      const parsed = parseRepairOrderAnalysisCategoryTotals(workbook, monthLabel, category)
      if(isLast) appendBucket(lastBuckets, category, parsed)
      else appendBucket(currentBuckets, category, parsed)
      return
    }

    fallbackRows = [...fallbackRows, ...parseAdvisorSalesSummaryWorkbook(workbook)]
  })

  const currentBucketRows = [...currentBuckets.cp, ...currentBuckets.warranty, ...currentBuckets.internal]
  const lastBucketRows = [...lastBuckets.cp, ...lastBuckets.warranty, ...lastBuckets.internal]
  if(currentBucketRows.length) currentRows = mergeAdvisorSalesRows(currentBucketRows, 'June MTD')
  if(lastBucketRows.length) lastRows = mergeAdvisorSalesRows(lastBucketRows, 'May MTD')

  if(currentRows.length || lastRows.length){
    const currentWithProjection = applyOpenRosToProjections(currentRows)
    return [...currentWithProjection, ...lastRows].filter(r => isDashboardAdvisor(r.advisor))
  }

  return fallbackRows
}

function parseDashboardUploadSalesWorkbook(workbook){
  const ws = workbook.Sheets['Pace'] || workbook.Sheets['PACE'] || workbook.Sheets[workbook.SheetNames[0]]
  if(!ws) return []

  const raw = XLSX.utils.sheet_to_json(ws, { header: 1, defval: '' })
  const headerRow = raw[30] || []
  const elapsed = cleanCurrencyNumber(raw?.[1]?.[12]) || 0
  const totalDays = cleanCurrencyNumber(raw?.[2]?.[12]) || 0
  const factor = elapsed && totalDays ? totalDays / elapsed : 1

  const shortNameMap = {
    toren: 'Toren Hamilton',
    lane: 'Lane Depriest',
    liam: 'Liam Weisbrodt',
    garrett: 'Garrett Willey',
    stan: 'Stanley Snyder',
    stanley: 'Stanley Snyder',
    matt: 'Matthew Oswald',
    matthew: 'Matthew Oswald',
  }

  function cell(rowIndex, colIndex){
    return cleanCurrencyNumber(raw?.[rowIndex]?.[colIndex]) || 0
  }

  function advisorFromHeader(value){
    const rawName = String(value || '').trim()
    const key = rawName.toLowerCase().replace(/[^a-z]/g,'')
    return shortNameMap[key] || activeAdvisorName(rawName) || salesAdvisorName(rawName)
  }

  const output = []

  for(let col = 2; col <= 7; col++){
    const advisor = advisorFromHeader(headerRow[col])
    if(!advisor || !isDashboardAdvisor(advisor)) continue

    const cpRos = cell(36, col)
    const soldHours = cell(37, col)
    const laborSales = cell(39, col)
    const laborGross = cell(40, col)
    const partsSales = cell(44, col)
    const partsGross = cell(45, col)
    const totalGross = laborGross + partsGross
    const totalSales = laborSales + partsSales
    const elr = cell(34, col)
    const hoursPerRo = cell(33, col) || (cpRos ? soldHours / cpRos : 0)
    const gpPercent = totalSales ? (totalGross / totalSales) * 100 : 0
    const projectedGross = totalGross * factor
    const projectedRos = cpRos * factor
    const projectedSoldHours = soldHours * factor

    output.push({
      month_label: 'June MTD',
      advisor,
      cp_ros: cpRos,
      warranty_ros: 0,
      ros: cpRos,
      total_ros: cpRos,
      sold_hours: soldHours,
      customer_pay_gp: totalGross,
      cp_gross: totalGross,
      warranty_gross: 0,
      warranty_gp: 0,
      total_warranty_gp: 0,
      total_gross: totalGross,
      parts_gp: partsGross,
      parts_gross: partsGross,
      labor_gross: laborGross,
      cp_labor_gross: laborGross,
      cp_parts_gross: partsGross,
      warranty_labor_gross: 0,
      warranty_parts_gross: 0,
      internal_labor_gross: 0,
      internal_parts_gross: 0,
      labor_sales: laborSales,
      elr,
      net_elr: elr,
      gp_percent: gpPercent,
      labor_gp_percent: laborSales ? (laborGross / laborSales) * 100 : 0,
      parts_gp_percent: partsSales ? (partsGross / partsSales) * 100 : 0,
      avg_cp_hours_ro: hoursPerRo,
      avg_hours_ro: hoursPerRo,
      projected_ros: projectedRos,
      projected_sold_hours: projectedSoldHours,
      projected_customer_pay_gp: projectedGross,
      projected_cp_gross: projectedGross,
      projected_warranty_gross: 0,
      projected_warranty_gp: 0,
      projected_total_warranty_gp: 0,
      projected_total_gross: projectedGross,
    })
  }

  return output
}

function parseAdvisorProjectionSheet(workbook){
  const ws = workbook.Sheets['June Projection']
  if(!ws) return []
  const rows = XLSX.utils.sheet_to_json(ws, { defval: '' })
  return rows.map((r)=>({
    advisor: salesAdvisorName(r['Advisor']),
    projected_ros: cleanCurrencyNumber(r['Projected ROs']),
    projected_sold_hours: cleanCurrencyNumber(r['Projected Sold Hrs']),
    projected_warranty_gp: cleanCurrencyNumber(r['Projected Warr GP']),
    projected_parts_gp: cleanCurrencyNumber(r['Projected Parts GP']),
    projected_total_warranty_gp: cleanCurrencyNumber(r['Projected Warranty Net GP $'] ?? r['Projected Total Warr GP']),
    projected_customer_pay_gp: cleanCurrencyNumber(r['Projected CP Net GP $'] ?? r['Projected GP$']),
  })).filter(r => r.advisor)
}

function parseAdvisorSalesSummaryWorkbook(workbook){
  const dashboardRows = parseDashboardUploadSalesWorkbook(workbook)
  if(dashboardRows.length){
    return dashboardRows.filter(r => ['Toren Hamilton','Lane Depriest','Liam Weisbrodt','Stanley Snyder','Garrett Willey','Matthew Oswald'].some(a => isSameAdvisorName(a, r.advisor)))
  }

  const june = parseAdvisorSalesSheet(workbook, 'June MTD', 'June MTD')
  const may = parseAdvisorSalesSheet(workbook, 'May MTD', 'May MTD')
  const projections = parseAdvisorProjectionSheet(workbook)
  const projectionMap = new Map(projections.map(p => [normalizeAdvisorMatchName(p.advisor), p]))
  const combined = [...june, ...may].map(row => {
    const projection = row.month_label === 'June MTD' ? projectionMap.get(normalizeAdvisorMatchName(row.advisor)) : null
    return projection ? {...row, ...projection} : row
  })
  return combined.filter(r => ['Toren Hamilton','Lane Depriest','Liam Weisbrodt','Stanley Snyder','Garrett Willey','Matthew Oswald'].some(a => isSameAdvisorName(a, r.advisor)))
}

function getLatestSalesRows(rows = [], advisorFilter = ''){
  const filtered = advisorFilter ? rows.filter(r => isSameAdvisorName(r.advisor, advisorFilter)) : rows
  const june = filtered.filter(r => r.month_label === 'June MTD')
  return june.length ? june : filtered.filter(r => r.month_label === 'May MTD')
}

