function rentalAgingClass(row){
  const days = Number(row.days_in_rental || 0)
  if(days >= 20) return 'rental-row-critical'
  if(days >= 10) return 'rental-row-red'
  if(days > 3) return 'rental-row-yellow'
  return 'rental-row-green'
}

function RentalsOutPage({ advisorFilter = '' }){
  const [rows,setRows] = useState([])
  const [error,setError] = useState('')
  const [loading,setLoading] = useState(true)

  useEffect(()=>{
    let active = true
    async function load(){
      try{
        setLoading(true)
        const data = await getRentalsOut()
        if(active) setRows(advisorFilter ? filterByAdvisor(Array.isArray(data) ? data : [], advisorFilter) : (Array.isArray(data) ? data : []))
      }catch(e){ if(active) setError(e.message || String(e)) }
      finally{ if(active) setLoading(false) }
    }
    load()
    return ()=>{ active = false }
  }, [])

  const total = rows.length
  const yellow = rows.filter(r => Number(r.days_in_rental || 0) > 3 && Number(r.days_in_rental || 0) < 10).length
  const red = rows.filter(r => Number(r.days_in_rental || 0) >= 10 && Number(r.days_in_rental || 0) < 20).length
  const critical = rows.filter(r => Number(r.days_in_rental || 0) >= 20).length

  return (
    <>
      {error && <div className="error">Rentals load failed: {error}</div>}
      {loading && <div className="management-status">Loading Rentals...</div>}
      <div className="simple-csi-kpis">
        <div className="card"><div className="label">Rentals Out</div><div className="value green">{total}</div></div>
        <div className="card"><div className="label">Yellow &gt; 3 Days</div><div className="value orange">{yellow}</div></div>
        <div className="card"><div className="label">Red ≥ 10 Days</div><div className="value red">{red}</div></div>
        <div className="card"><div className="label">Critical ≥ 20 Days</div><div className="value red">{critical}</div></div>
      </div>
      <CdkActualSortableTable
        title="Rentals Out"
        rows={rows}
        defaultSort="days_in_rental"
        rowClassName={rentalAgingClass}
        columns={[
          {key:'customer', label:'Customer'},
          {key:'advisor', label:'Advisor'},
          {key:'ro', label:'RO'},
          {key:'date_out', label:'Date Out'},
          {key:'days_in_rental', label:'Days Out'},
          
        ]}
        numberColumns={['ro','days_in_rental','days_in_service']}
      />
    </>
  )
}

