function WarrantyAdjustmentScoreboard({ rows = [] }){
  const grouped = Array.from(rows.reduce((map,row)=>{
    const advisor = advisorIdMap(row.advisor || row.advisor_id || 'No Advisor')
    if(!map.has(advisor)) map.set(advisor, { advisor, count:0, amount:0 })
    const item = map.get(advisor)
    item.count += 1
    item.amount += Number(row.adjustment_amount || 0)
    return map
  }, new Map()).values()).sort((a,b)=>Math.abs(b.amount)-Math.abs(a.amount))

  return (
    <div className="panel">
      <div className="panel-head">
        <div>
          <div className="panel-title">Warranty Adjustment Scoreboard</div>
          <div className="small">Training opportunities by advisor</div>
        </div>
      </div>
      <div className="table-wrap">
        <table>
          <thead><tr><th>Advisor</th><th>Adjustments</th><th>Total $</th></tr></thead>
          <tbody>
            {grouped.map(r=>(
              <tr key={r.advisor}>
                <td><b>{r.advisor}</b></td>
                <td>{r.count}</td>
                <td className={r.amount < 0 ? 'red' : 'orange'}>${r.amount.toLocaleString(undefined,{minimumFractionDigits:2,maximumFractionDigits:2})}</td>
              </tr>
            ))}
            {grouped.length === 0 && <tr><td colSpan="3">No warranty adjustments loaded.</td></tr>}
          </tbody>
        </table>
      </div>
    </div>
  )
}

